class AgenticEvidenceOSTests(unittest.TestCase):
    def test_raw_assertion_schema_is_contract_blind_and_has_no_score_fields(self):
        raw_field_names = {field.name for field in fields(RawAssertion)}

        self.assertEqual(forbidden_extractor_field_overlap(raw_field_names), ())
        self.assertFalse(FORBIDDEN_EXTRACTOR_FIELDS & raw_field_names)

    def test_extractor_forbidden_fields_match_score_authority_boundary(self):
        self.assertTrue(
            {
                "verified",
                "current_score_eligible",
                "source_tier",
                "issuer_scoped",
                "candidate_primitive_id",
                "primitive_id",
                "score",
                "stage",
                "hard_break",
            }.issubset(FORBIDDEN_EXTRACTOR_FIELDS)
        )

    def test_provider_json_schemas_preserve_stage_authority_boundaries(self):
        validate_claim_extractor_provider_schema(RAW_ASSERTION_OUTPUT_JSON_SCHEMA)
        validate_adjudication_provider_schema(ADJUDICATION_OUTPUT_JSON_SCHEMA)
        validate_primitive_mapping_provider_schema(PRIMITIVE_MAPPING_OUTPUT_JSON_SCHEMA)
        validate_follow_up_provider_schema(FOLLOW_UP_OUTPUT_JSON_SCHEMA)

        bad_extractor = json.loads(json.dumps(RAW_ASSERTION_OUTPUT_JSON_SCHEMA))
        bad_extractor["properties"]["raw_assertions"]["items"]["properties"]["current_score_eligible"] = {
            "type": "boolean"
        }
        with self.assertRaisesRegex(ValueError, "current_score_eligible"):
            validate_claim_extractor_provider_schema(bad_extractor)

        bad_adjudicator = json.loads(json.dumps(ADJUDICATION_OUTPUT_JSON_SCHEMA))
        bad_adjudicator["properties"]["primitive_id"] = {"type": "string"}
        with self.assertRaisesRegex(ValueError, "primitive_id"):
            validate_adjudication_provider_schema(bad_adjudicator)

        bad_mapper = json.loads(json.dumps(PRIMITIVE_MAPPING_OUTPUT_JSON_SCHEMA))
        bad_mapper["properties"]["mappings"]["items"]["properties"]["score"] = {"type": "number"}
        with self.assertRaisesRegex(ValueError, "score"):
            validate_primitive_mapping_provider_schema(bad_mapper)

        bad_follow_up = json.loads(json.dumps(FOLLOW_UP_OUTPUT_JSON_SCHEMA))
        bad_follow_up["properties"]["stage"] = {"type": "string"}
        with self.assertRaisesRegex(ValueError, "stage"):
            validate_follow_up_provider_schema(bad_follow_up)

    def test_codex_provider_rejects_polluted_extractor_schema_before_cli_call(self):
        document, anchor, _raw = _current_target_risk_fixture()
        bad_schema = json.loads(json.dumps(RAW_ASSERTION_OUTPUT_JSON_SCHEMA))
        bad_schema["properties"]["raw_assertions"]["items"]["properties"]["current_score_eligible"] = {
            "type": "boolean"
        }
        provider = CodexCLIAgenticEvidenceProvider()

        with (
            patch("e2r.agentic.codex_provider.RAW_ASSERTION_OUTPUT_JSON_SCHEMA", bad_schema),
            patch("e2r.agentic.codex_provider._run_codex_command") as run_codex,
            self.assertRaisesRegex(ValueError, "current_score_eligible"),
        ):
            provider.extract(
                ClaimExtractionInput(
                    target_entity_id="CORP_TARGET",
                    target_names=("Target issuer",),
                    as_of_date=date(2026, 6, 21),
                    document=document,
                    document_text="Target issuer disclosed that its auditor issued an adverse opinion.",
                    anchors=(anchor,),
                )
            )

        run_codex.assert_not_called()

    def test_global_adversarial_suite_has_named_regressions_for_all_required_cases(self):
        tests_root = Path(__file__).resolve().parent
        test_methods = adversarial_acceptance_cli.discover_test_methods(tests_root)
        coverage = {
            str(case["case_id"]): tuple(str(name) for name in case["representative_tests"])
            for case in adversarial_acceptance_cli.ADVERSARIAL_CASES
        }

        missing = {
            case_id: tuple(name for name in required if name not in test_methods)
            for case_id, required in coverage.items()
            if any(name not in test_methods for name in required)
        }

        self.assertEqual(len(coverage), 24)
        self.assertEqual(missing, {})

    def test_evidence_mention_schema_is_quarantined_not_score_or_claim_authority(self):
        mention_field_names = {field.name for field in fields(EvidenceMention)}

        self.assertFalse(FORBIDDEN_EXTRACTOR_FIELDS & mention_field_names)
        self.assertNotIn("claim_id", mention_field_names)
        self.assertNotIn("primitive_id", mention_field_names)

    def test_legacy_parser_fields_become_mentions_not_score_claims(self):
        mentions = mentions_from_parsed_fields(
            evidence_id="news:target:2020-03-18",
            parsed_fields={
                "accounting_or_trust_issue": True,
                "claim_ledger_version": "legacy",
                "compiled_claim_ids_by_primitive": {
                    "accounting_or_trust_issue": ("CLM-LEGACY",),
                },
            },
            source_kind=MentionSourceKind.LEGACY_PARSER_FIELD,
            subject_hint="Worldex",
            text_hint="Worldex audit opinion was unqualified; Samsung was a customer.",
        )

        self.assertEqual(len(mentions), 1)
        self.assertEqual(mentions[0].field_name, "accounting_or_trust_issue")
        self.assertFalse(mentions[0].score_admissible())
        self.assertFalse(hasattr(mentions[0], "claim_id"))

    def test_agentic_document_prompt_text_is_bounded_for_large_pdf_text(self):
        text = "HBM 완판 근거\n" + ("x" * (_AGENTIC_EVIDENCE_DOCUMENT_TEXT_LIMIT + 500))

        prompt_text = _agentic_document_prompt_text(text)

        self.assertLessEqual(len(prompt_text), _AGENTIC_EVIDENCE_DOCUMENT_TEXT_LIMIT)
        self.assertTrue(prompt_text.startswith("HBM 완판 근거"))
        self.assertNotIn("x" * 9000, prompt_text)

    def test_agentic_document_prompt_chunks_include_later_pdf_text_with_bounds(self):
        late_text = "SK하이닉스는 HBM 고객 물량 배정과 capacity 선점을 설명했다."
        text = (
            "첫 번째 리포트 구간\n"
            + ("x" * (_AGENTIC_EVIDENCE_DOCUMENT_TEXT_LIMIT + 500))
            + "\n"
            + late_text
        )

        chunks = _agentic_document_prompt_chunks(text)

        self.assertEqual(len(chunks), _AGENTIC_EVIDENCE_CHUNK_LIMIT_PER_DOCUMENT)
        self.assertTrue(all(len(chunk) <= _AGENTIC_EVIDENCE_DOCUMENT_TEXT_LIMIT for chunk in chunks))
        self.assertIn(late_text, chunks[-1])

    def test_agentic_document_prompt_chunks_use_relevance_window_for_far_capacity_terms(self):
        late_text = "TargetIssuer HBM capacity remains constrained and pre-sold to customers."
        text = (
            "TargetIssuer operating profit forecast table.\n"
            + ("x" * (_AGENTIC_EVIDENCE_DOCUMENT_TEXT_LIMIT * 2 + 500))
            + "\n"
            + late_text
        )

        chunks = _agentic_document_prompt_chunks(
            text,
            relevance_terms={
                "hbm": 5.0,
                "capacity": 5.0,
                "pre": 2.0,
                "sold": 2.0,
                "customer": 4.0,
            },
        )

        self.assertEqual(len(chunks), _AGENTIC_EVIDENCE_CHUNK_LIMIT_PER_DOCUMENT)
        self.assertIn("operating profit forecast", chunks[0])
        self.assertIn(late_text, chunks[-1])
        self.assertTrue(all(len(chunk) <= _AGENTIC_EVIDENCE_DOCUMENT_TEXT_LIMIT for chunk in chunks))

    def test_agentic_document_inputs_keep_bounded_chunks_for_one_long_document(self):
        late_text = "SK하이닉스는 HBM 고객 물량 배정과 capacity 선점을 설명했다."
        text = (
            "SK하이닉스 리포트 앞부분\n"
            + ("x" * (_AGENTIC_EVIDENCE_DOCUMENT_TEXT_LIMIT + 500))
            + "\n"
            + late_text
        )
        result = SearchResult(
            title="SK하이닉스 HBM 리포트",
            url="https://example.com/skhynix-hbm.pdf",
            source="fixture-report",
            published_at=datetime(2026, 6, 1, 9),
            is_pdf=True,
            is_report_domain=True,
        )
        web_result = WebResearchResult(
            company_name="SK하이닉스",
            symbol="000660",
            market=Market.KR,
            as_of_date=date(2026, 6, 21),
            query_plan=QueryPlan(
                company_name="SK하이닉스",
                symbol="000660",
                sector="semiconductor",
                market=Market.KR,
                as_of_date=date(2026, 6, 21),
                queries=(),
            ),
            queries_run=(),
            search_results=(result,),
            ranked_results=(RankedSearchResult(result=result, score=99.0),),
            selected_results=(RankedSearchResult(result=result, score=99.0),),
            fetched_documents=(
                FetchResult(
                    url=result.url,
                    ok=True,
                    text=text,
                    content_type="application/pdf",
                    fetched_at=datetime(2026, 6, 21, 8),
                ),
            ),
            parsed_reports=(),
            parsed_news=(),
        )

        rows = _agentic_document_inputs(
            inputs=FreeWebResearchInput(
                company_name="SK하이닉스",
                symbol="000660",
                sector="semiconductor",
                market=Market.KR,
                as_of_date=date(2026, 6, 21),
            ),
            web_result=web_result,
        )

        self.assertEqual(len(rows), _AGENTIC_EVIDENCE_CHUNK_LIMIT_PER_DOCUMENT)
        self.assertEqual(len({row[0].document_id for row in rows}), 1)
        self.assertEqual(len({row[2][0].anchor_id for row in rows}), len(rows))
        self.assertIn("SK하이닉스 HBM 리포트", rows[0][1])
        self.assertIn(late_text, rows[-1][1])

    def test_same_url_revised_content_gets_new_document_anchor_and_claim_ids(self):
        url = "https://example.com/targetissuer-hbm-update"
        original_text = "TargetIssuer said capacity allocation remains under customer review."
        revised_text = "TargetIssuer said capacity allocation is signed with Customer A."
        original = EvidenceDocument.from_text(
            text=original_text,
            canonical_url=url,
            source_type=SourceType.NEWS,
            source_name="fixture-news",
            published_at=datetime(2026, 6, 1, 9),
            available_at=datetime(2026, 6, 1, 9),
            revision_id="v1",
            parser_version="test",
        )
        revised = EvidenceDocument.from_text(
            text=revised_text,
            canonical_url=url,
            source_type=SourceType.NEWS,
            source_name="fixture-news",
            published_at=datetime(2026, 6, 1, 9),
            available_at=datetime(2026, 6, 2, 9),
            revision_id="v2",
            parser_version="test",
        )
        original_anchor = EvidenceAnchor.text_span(
            document=original,
            document_text=original_text,
            exact_text="capacity allocation remains under customer review",
        )
        revised_anchor = EvidenceAnchor.text_span(
            document=revised,
            document_text=revised_text,
            exact_text="capacity allocation is signed with Customer A",
        )
        original_claim = AdjudicatedClaim.from_raw(
            raw=RawAssertion(
                raw_assertion_id="RAW-REVISED-URL",
                anchor_id=original_anchor.anchor_id,
                subject_text="TargetIssuer",
                predicate="capacity allocation status",
                object_text="under customer review",
                exact_quote=original_anchor.exact_text,
            ),
            document=original,
            anchor=original_anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.CONDITIONAL,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2026, 6, 1),
        )
        revised_claim = AdjudicatedClaim.from_raw(
            raw=RawAssertion(
                raw_assertion_id="RAW-REVISED-URL",
                anchor_id=revised_anchor.anchor_id,
                subject_text="TargetIssuer",
                predicate="capacity allocation status",
                object_text="signed with Customer A",
                exact_quote=revised_anchor.exact_text,
            ),
            document=revised,
            anchor=revised_anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.POSITIVE,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2026, 6, 2),
        )
        ledger = AppendOnlyEvidenceLedger()

        ledger.append_claim(original_claim)
        ledger.append_claim(revised_claim)

        self.assertEqual(original.canonical_url, revised.canonical_url)
        self.assertNotEqual(original.content_hash, revised.content_hash)
        self.assertNotEqual(original.document_id, revised.document_id)
        self.assertNotEqual(original_anchor.anchor_id, revised_anchor.anchor_id)
        self.assertNotEqual(original_claim.claim_id, revised_claim.claim_id)
        self.assertEqual(len(ledger.claims), 2)

