    def test_agentic_document_limit_merges_chunks_before_workflow_compile(self):
        contract = load_evidence_contracts_v2()["C06_HBM_MEMORY_CUSTOMER_CAPACITY"]
        chunk_a = "TargetIssuer HBM customer allocation capacity pre sold."
        chunk_b = "TargetIssuer free cash flow and consensus revision bridge."
        document_text = f"{chunk_a}\n\n{chunk_b}"
        report_document = EvidenceDocument.from_text(
            text=document_text,
            canonical_url="https://reports.example.com/targetissuer-hbm.pdf",
            source_type=SourceType.RESEARCH_REPORT,
            source_name="FixtureBroker",
            published_at=date(2026, 6, 1),
        )
        other_text = "TargetIssuer HBM revenue visibility contract."
        other_document = EvidenceDocument.from_text(
            text=other_text,
            canonical_url="https://news.example.com/targetissuer-contract",
            source_type=SourceType.NEWS,
            source_name="FixtureNews",
            published_at=date(2026, 6, 1),
        )
        rows = (
            (
                report_document,
                chunk_a,
                (
                    EvidenceAnchor.text_span(
                        document=report_document,
                        document_text=document_text,
                        exact_text=chunk_a,
                        locator="document:prompt_chunk:0",
                    ),
                ),
            ),
            (
                report_document,
                chunk_b,
                (
                    EvidenceAnchor.text_span(
                        document=report_document,
                        document_text=document_text,
                        exact_text=chunk_b,
                        locator="document:prompt_chunk:1",
                    ),
                ),
            ),
            (
                other_document,
                other_text,
                (
                    EvidenceAnchor.text_span(
                        document=other_document,
                        document_text=other_text,
                        exact_text=other_text,
                        locator="document:full_text_excerpt",
                    ),
                ),
            ),
        )

        selected = _limit_agentic_document_inputs(
            rows,
            contract=contract,
            target_names=("TargetIssuer",),
            document_limit=3,
        )

        self.assertEqual(len({row[0].document_id for row in selected}), len(selected))
        merged_report = next(row for row in selected if row[0].document_id == report_document.document_id)
        self.assertIn(chunk_a, merged_report[1])
        self.assertIn(chunk_b, merged_report[1])
        self.assertEqual(len({anchor.anchor_id for anchor in merged_report[2]}), 2)

