    def test_c06_cash_bridge_freshness_stales_old_counter_claims(self):
        contract = load_evidence_contracts_v2()["C06_HBM_MEMORY_CUSTOMER_CAPACITY"]
        old_text = "TargetIssuer reported negative free cash flow in FY2023."
        fresh_text = "TargetIssuer reported positive operating cash flow in 2026 Q1."
        old_document = EvidenceDocument.from_text(
            text=old_text,
            canonical_url="feature://target/financial_actual/2023-12-31",
            source_type=SourceType.XBRL,
            source_name="FixtureXBRL",
            published_at=date(2024, 4, 1),
            available_at=date(2024, 4, 1),
        )
        fresh_document = EvidenceDocument.from_text(
            text=fresh_text,
            canonical_url="feature://target/financial_actual/2026-03-31",
            source_type=SourceType.XBRL,
            source_name="FixtureXBRL",
            published_at=date(2026, 5, 15),
            available_at=date(2026, 5, 15),
        )
        old_anchor = EvidenceAnchor.text_span(
            document=old_document,
            document_text=old_text,
            exact_text="negative free cash flow in FY2023",
        )
        fresh_anchor = EvidenceAnchor.text_span(
            document=fresh_document,
            document_text=fresh_text,
            exact_text="positive operating cash flow in 2026 Q1",
        )
        old_claim = AdjudicatedClaim.from_raw(
            raw=RawAssertion(
                raw_assertion_id="RAW-OLD-FCF",
                anchor_id=old_anchor.anchor_id,
                subject_text="TargetIssuer",
                predicate="free cash flow",
                object_text="negative",
                exact_quote=old_anchor.exact_text,
            ),
            document=old_document,
            anchor=old_anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.NEGATIVE,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2023, 12, 31),
        )
        fresh_claim = AdjudicatedClaim.from_raw(
            raw=RawAssertion(
                raw_assertion_id="RAW-FRESH-CFO",
                anchor_id=fresh_anchor.anchor_id,
                subject_text="TargetIssuer",
                predicate="operating cash flow",
                object_text="positive",
                exact_quote=fresh_anchor.exact_text,
            ),
            document=fresh_document,
            anchor=fresh_anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.POSITIVE,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2026, 3, 31),
        )
        ledger = AppendOnlyEvidenceLedger()
        ledger.append_claim(old_claim)
        ledger.append_claim(fresh_claim)
        ledger.append_mapping(
            PrimitiveMappingProposal.build(
                claim_id=old_claim.claim_id,
                archetype_id=contract.archetype_id,
                primitive_id="cash_or_revision_conversion",
                support_direction=SupportDirection.COUNTER,
                mapping_status=MappingStatus.ACCEPTED,
                rationale="old negative cash flow",
            )
        )
        ledger.append_mapping(
            PrimitiveMappingProposal.build(
                claim_id=fresh_claim.claim_id,
                archetype_id=contract.archetype_id,
                primitive_id="cash_or_revision_conversion",
                support_direction=SupportDirection.SUPPORT,
                mapping_status=MappingStatus.ACCEPTED,
                rationale="fresh operating cash flow",
            )
        )

        states = aggregate_primitive_states(
            ledger=ledger,
            contract=contract,
            as_of_date=date(2026, 6, 28),
        )

        self.assertEqual(states["cash_or_revision_conversion"].status, PrimitiveStatus.PRESENT_CURRENT)
        self.assertEqual(states["cash_or_revision_conversion"].support_claim_ids, (fresh_claim.claim_id,))
        self.assertEqual(states["cash_or_revision_conversion"].counter_claim_ids, ())

