    def test_codex_agentic_extractor_retries_once_after_provider_error(self):
        document, anchor, raw = _current_target_risk_fixture()
        provider = _SequenceCodexProvider(
            (
                None,
                {
                    "status": "ok",
                    "blocked_reason": None,
                    "raw_assertions": [
                        {
                            "raw_assertion_id": raw.raw_assertion_id,
                            "anchor_id": anchor.anchor_id,
                            "subject_text": raw.subject_text,
                            "predicate": raw.predicate,
                            "object_text": raw.object_text,
                            "value": raw.value,
                            "unit": raw.unit,
                            "polarity_proposal": raw.polarity_proposal.value,
                            "modality": raw.modality,
                            "certainty": raw.certainty,
                            "event_date_text": raw.event_date_text,
                            "effective_period_text": raw.effective_period_text,
                            "exact_quote": raw.exact_quote,
                            "span": raw.span,
                            "related_entity_texts": list(raw.related_entity_texts),
                            "extractor_model": raw.extractor_model,
                            "extractor_prompt_hash": raw.extractor_prompt_hash,
                        }
                    ],
                },
            )
        )

        output = provider.extract(
            ClaimExtractionInput(
                target_entity_id="CORP_TARGET",
                target_names=("Target issuer",),
                as_of_date=date(2026, 6, 21),
                document=document,
                document_text="Target issuer disclosed that its auditor issued an adverse opinion.",
                anchors=(anchor,),
            )
        )

        self.assertIsInstance(output, ClaimExtractionOutput)
        self.assertEqual(len(output.raw_assertions), 1)
        self.assertEqual(len(provider.prompts), 2)
        self.assertIn("previous attempt did not produce a parseable JSON object", provider.prompts[1])
        self.assertIn("compact_document_text", provider.prompts[1])
        self.assertNotIn("green_gate", provider.prompts[1].lower())

