    def test_claim_extraction_messages_include_available_anchor_ids(self):
        text = "Target issuer disclosed a direct customer allocation."
        document = EvidenceDocument.from_text(
            text=text,
            canonical_url="https://example.com/target-allocation",
            source_type=SourceType.NEWS,
            source_name="FixtureNews",
            published_at=date(2026, 6, 1),
        )
        anchor = EvidenceAnchor.text_span(
            document=document,
            document_text=text,
            exact_text="direct customer allocation",
        )

        messages = build_claim_extraction_messages(
            ClaimExtractionInput(
                target_entity_id="CORP_TARGET",
                target_names=("Target issuer",),
                as_of_date=date(2026, 6, 21),
                document=document,
                document_text=text,
                anchors=(anchor,),
            )
        )

        user_payload = messages[1]["content"]
        decoded_payload = json.loads(user_payload)
        self.assertIn(anchor.anchor_id, user_payload)
        self.assertIn("available_anchors", user_payload)
        self.assertIn("normalized_value", decoded_payload["available_anchors"][0])
        rules_text = "\n".join(decoded_payload["extraction_rules"])
        self.assertIn("concrete source-specific operating facts", rules_text)
        self.assertIn("Do not spend raw assertion slots on target price", rules_text)
        self.assertIn("mixes different effective periods", rules_text)
        self.assertIn("effective_period_text", rules_text)
        self.assertIn("title, subtitle, or lead paragraph", rules_text)
        self.assertIn("policy, tax credit, subsidy", rules_text)
        self.assertFalse(messages_contain_forbidden_extractor_context(messages))

