        self.assertTrue(decoded_payload["untrusted_document_text_compacted"])
        self.assertEqual(decoded_payload["untrusted_document_text_chars"], len(long_text))
        self.assertLess(len(decoded_payload["untrusted_document_text"]), len(long_text))
        self.assertIn(target_sentence, decoded_payload["untrusted_document_text"])
        self.assertNotIn(
            "irrelevant background. irrelevant background. irrelevant background. irrelevant background.",
            decoded_payload["untrusted_document_text"],
        )
        self.assertFalse(messages_contain_forbidden_extractor_context(messages))

