    def test_codex_adjudicator_splits_duplicate_raw_assertion_ids_out_of_batch(self):
        class _Provider(CodexCLIAgenticEvidenceProvider):
            def __init__(self):
                CodexCLIAgenticEvidenceProvider.__init__(self)
                object.__setattr__(self, "single_prompts", [])

            def _run_json(self, *, schema, prompt):
                if "adjudications" in (schema.get("properties") or {}):
                    raise AssertionError("duplicate raw_assertion_id batch should not be used")
                self.single_prompts.append(prompt)
                subject = "CORP_A" if "CORP_A" in prompt else "CORP_B"
                return {
                    "subject_entity_id": subject,
                    "relation_to_target": "SELF",
                    "directness": "DIRECT",
                    "target_scope_status": "DIRECT",
                    "polarity": "POSITIVE",
                    "temporal_status": "CURRENT",
                    "semantic_status": "PASS",
                    "investigation_status": "COMPLETE",
                    "event_date": None,
                    "effective_start": None,
                    "effective_end": None,
                    "rationale": f"single adjudication for {subject}",
                }

        def make_input(target_entity_id: str, text: str) -> AdjudicationInput:
            document = EvidenceDocument.from_text(
                text=text,
                canonical_url=f"https://example.com/{target_entity_id}",
                source_type=SourceType.NEWS,
                source_name="FixtureNews",
                published_at=date(2026, 5, 15),
            )
            anchor = EvidenceAnchor.text_span(document=document, document_text=text, exact_text=text)
            raw = RawAssertion(
                raw_assertion_id="RA-001",
                anchor_id=anchor.anchor_id,
                subject_text=target_entity_id,
                predicate="reported",
                object_text=text,
                polarity_proposal=Polarity.POSITIVE,
                exact_quote=text,
            )
            return AdjudicationInput(
                raw_assertion=raw,
                document=document,
                anchor=anchor,
                target_entity_id=target_entity_id,
                entity_registry=EntityRegistry(
                    {
                        target_entity_id: EntityRecord(
                            entity_id=target_entity_id,
                            legal_name=target_entity_id,
                            aliases=(),
                        )
                    }
                ),
                as_of_date=date(2026, 5, 15),
            )

        provider = _Provider()
        proposals = provider.adjudicate_many(
            (
                make_input("CORP_A", "CORP_A reported a current order backlog."),
                make_input("CORP_B", "CORP_B reported a current margin improvement."),
            )
        )

        self.assertEqual(len(provider.single_prompts), 2)
        self.assertEqual([proposal.subject_entity_id for proposal in proposals], ["CORP_A", "CORP_B"])

    def test_agentic_codex_provider_env_factory_builds_separated_bundle(self):
        bundle = build_agentic_evidence_provider_bundle_from_env(
            {
                "E2R_AGENTIC_EVIDENCE_PROVIDER": "codex",
                "E2R_CODEX_AGENTIC_MODEL": "gpt-agentic-fixture",
                "E2R_CODEX_AGENTIC_TIMEOUT_SECONDS": "45",
                "E2R_CODEX_AGENTIC_EXTRA_ARGS": "--strict-config",
            },
            working_directory="/repo",
        )

        self.assertIsNotNone(bundle)
        self.assertIsInstance(bundle.extractor, CodexCLIAgenticEvidenceProvider)
        self.assertIs(bundle.extractor, bundle.adjudicator)
        self.assertIs(bundle.extractor, bundle.mapper)
        self.assertIs(bundle.extractor, bundle.follow_up_planner)
        self.assertEqual(bundle.extractor.model, "gpt-agentic-fixture")
        self.assertEqual(bundle.extractor.timeout_seconds, 45.0)
        self.assertIn("--ignore-user-config", bundle.extractor.extra_args)
        self.assertIn("--ignore-rules", bundle.extractor.extra_args)
        self.assertIn("--strict-config", bundle.extractor.extra_args)
        command = bundle.extractor._command(schema_path=Path("/tmp/schema.json"), output_path=Path("/tmp/output.json"))
        self.assertIn("--ignore-user-config", command)
        self.assertIn("--ignore-rules", command)

