    def test_all_archetype_contracts_support_minimal_evidence_os_replay_smoke(self):
        contracts = load_evidence_contracts_v2(require_all_archetypes=True)

        for archetype_id, contract in contracts.items():
            with self.subTest(archetype_id=archetype_id):
                primitive_id = contract.required_primitives[0]
                risk_like = any(
                    token in primitive_id.casefold()
                    for token in ("accounting", "cancel", "delay", "failure", "hard_break", "halt", "lag", "risk", "trust")
                )
                quote = (
                    f"TargetIssuer source-backed fixture confirms current negative risk for {primitive_id}."
                    if risk_like
                    else f"TargetIssuer source-backed fixture supports {primitive_id}."
                )
                if (
                    any(token in primitive_id.casefold() for token in ("asp", "pass_through", "price", "pricing", "spread"))
                    and "price_only" not in primitive_id.casefold()
                ):
                    quote = (
                        f"TargetIssuer source-backed fixture confirms target margin expansion and "
                        f"spread expansion for {primitive_id}."
                    )
                document = EvidenceDocument.from_text(
                    text=quote,
                    canonical_url=f"fixture://synthetic/{archetype_id}/{primitive_id}",
                    source_type=SourceType.RESEARCH_REPORT,
                    source_name="synthetic_contract_replay_fixture",
                    published_at=date(2026, 1, 15),
                    available_at=date(2026, 1, 15),
                    parser_version="synthetic-contract-smoke",
                )
                anchor = EvidenceAnchor.text_span(
                    document=document,
                    document_text=quote,
                    exact_text=quote,
                )
                raw = RawAssertion(
                    raw_assertion_id=f"RAW-{archetype_id}",
                    anchor_id=anchor.anchor_id,
                    subject_text="TargetIssuer",
                    predicate=f"supports {primitive_id}",
                    object_text=quote,
                    polarity_proposal=Polarity.NEGATIVE if risk_like else Polarity.POSITIVE,
                    event_date_text="2026-01-15",
                    exact_quote=quote,
                )

                result = EvidenceWorkflowOrchestrator(
                    extractor=FakeClaimExtractorProvider(ClaimExtractionOutput((raw,))),
                    adjudicator=FakeClaimAdjudicatorProvider(
                        AdjudicationProposal(
                            subject_entity_id="KR:TEST",
                            relation_to_target=RelationToTarget.SELF,
                            directness=Directness.DIRECT,
                            target_scope_status=TargetScopeStatus.DIRECT,
                            polarity=Polarity.NEGATIVE if risk_like else Polarity.POSITIVE,
                            temporal_status=TemporalStatus.CURRENT,
                            semantic_status=SemanticStatus.PASS_,
                            investigation_status=InvestigationStatus.COMPLETE,
                            event_date=date(2026, 1, 15),
                        )
                    ),
                    mapper=_DynamicMapper(
                        primitive_id=primitive_id,
                        status=MappingStatus.ACCEPTED,
                        support_direction=SupportDirection.SUPPORT,
                    ),
                ).compile(
                    EvidenceCompilationInput(
                        target_entity_id="KR:TEST",
                        target_names=("TargetIssuer",),
                        as_of_date=date(2026, 6, 21),
                        document=document,
                        document_text=quote,
                        anchors=(anchor,),
                        entity_registry=EntityRegistry(),
                        contract=contract,
                        canonical_primitive_ids=contract.required_primitives,
                    )
                )
                primitive_states = aggregate_primitive_states(
                    ledger=result.ledger,
                    contract=contract,
                    as_of_date=date(2026, 6, 21),
                )
                contributions = build_component_score_contributions_from_rubric(
                    components={component_key: 10.0 for component_key in contract.score_rubric},
                    primitive_states=primitive_states,
                    score_rubric=contract.score_rubric,
                )

                self.assertEqual(len(result.ledger.claims), 1)
                self.assertEqual(len(result.ledger.mappings), 1)
                self.assertEqual(primitive_states[primitive_id].status, PrimitiveStatus.PRESENT_CURRENT)
                self.assertEqual(len(contributions), len(contract.score_rubric))

