        self.assertEqual(route_plans[0]["selected_candidate_tiers"], (1,))
        self.assertEqual(route_plans[0]["selected_candidate_official"], (True,))
        self.assertEqual(route_plans[0]["selected_candidate_cash_bridge_signal_counts"], (0,))
        self.assertEqual(route_plans[0]["selected_candidate_cash_bridge_signal_present"], (False,))
