    def test_agentic_primitive_gap_materiality_uses_contract_score_relevance(self):
        trace = AgenticEvidenceRuntimeTrace(
            status="completed",
            archetype_id="C06_HBM_MEMORY_CUSTOMER_CAPACITY",
            primitive_states=(
                PrimitiveStateV2("qualification_status", PrimitiveStatus.UNKNOWN),
                PrimitiveStateV2("contract_visibility", PrimitiveStatus.UNKNOWN),
                PrimitiveStateV2("customer_preorder_or_allocation", PrimitiveStatus.UNKNOWN),
            ),
        )

        gaps = _agentic_primitive_gap_context(
            trace,
            archetype_id="C06_HBM_MEMORY_CUSTOMER_CAPACITY",
        )
        material = _material_score_gaps(gaps)
        ordered = _follow_up_primitive_states(
            gaps,
            trace,
            archetype_id="C06_HBM_MEMORY_CUSTOMER_CAPACITY",
        )
        by_id = {state.primitive_id: state for state in ordered}

        self.assertTrue(any("qualification_status" in gap and "materiality:0.0" in gap for gap in gaps))
        self.assertTrue(any("contract_visibility" in gap and "materiality:0.0" in gap for gap in gaps))
        self.assertTrue(
            any("customer_preorder_or_allocation" in gap and "materiality:5.0" in gap for gap in gaps)
        )
        self.assertFalse(any("qualification_status" in gap for gap in material))
        self.assertFalse(any("contract_visibility" in gap for gap in material))
        self.assertTrue(any("customer_preorder_or_allocation" in gap for gap in material))
        self.assertEqual(by_id["qualification_status"].materiality_remaining_points, 0.0)
        self.assertEqual(by_id["contract_visibility"].materiality_remaining_points, 0.0)
        self.assertGreater(by_id["customer_preorder_or_allocation"].materiality_remaining_points, 0.0)

