    def test_agentic_append_only_filter_skips_previously_compiled_documents(self):
        old_text = "삼성전자 HBM 고객 물량 배정이 확인됐다."
        old_document = EvidenceDocument.from_text(
            text=old_text,
            canonical_url="https://news.example.com/old",
            source_type=SourceType.NEWS,
            source_name="fixture-news",
            published_at=date(2026, 6, 20),
        )
        old_anchor = EvidenceAnchor.text_span(
            document=old_document,
            document_text=old_text,
            exact_text="삼성전자 HBM 고객 물량 배정이 확인됐다.",
        )
        new_text = "삼성전자 HBM4 qualification 진행 상황이 새로 보도됐다."
        new_document = EvidenceDocument.from_text(
            text=new_text,
            canonical_url="https://news.example.com/new",
            source_type=SourceType.NEWS,
            source_name="fixture-news",
            published_at=date(2026, 6, 21),
        )
        new_anchor = EvidenceAnchor.text_span(
            document=new_document,
            document_text=new_text,
            exact_text="삼성전자 HBM4 qualification 진행 상황이 새로 보도됐다.",
        )

        kept, skipped_count = _filter_agentic_document_inputs_for_append_only(
            (
                (old_document, old_text, (old_anchor,)),
                (new_document, new_text, (new_anchor,)),
            ),
            skip_document_ids=(old_document.document_id,),
        )

        self.assertEqual(skipped_count, 1)
        self.assertEqual(tuple(row[0].document_id for row in kept), (new_document.document_id,))
        self.assertEqual(_agentic_trace_document_ids(AgenticEvidenceRuntimeTrace(document_ids=("DOC-X",))), ("DOC-X",))

