    def test_agentic_runtime_trace_merge_promotes_contradictions_over_present(self):
        previous = AgenticEvidenceRuntimeTrace(
            status="completed",
            primitive_states=(
                PrimitiveStateV2(
                    "hbm_capacity_pre_sold",
                    PrimitiveStatus.PRESENT_CURRENT,
                    support_claim_ids=("claim-positive",),
                ),
            ),
        )
        current = AgenticEvidenceRuntimeTrace(
            status="completed",
            primitive_states=(
                PrimitiveStateV2(
                    "hbm_capacity_pre_sold",
                    PrimitiveStatus.CONTRADICTED,
                    counter_claim_ids=("claim-counter",),
                ),
            ),
        )

        merged = _merge_agentic_evidence_runtime_traces(previous, current)
        state = merged.primitive_states[0]

        self.assertEqual(state.status, PrimitiveStatus.CONTRADICTED)
        self.assertEqual(state.support_claim_ids, ("claim-positive",))
        self.assertEqual(state.counter_claim_ids, ("claim-counter",))

