        self.assertEqual(consistency_events[0]["rejected_by_self_consistency_count"], 1)
        self.assertEqual(consistency_events[0]["mapping_agreement_omitted_count"], 0)
        agreement_text = " | ".join(consistency_events[0]["mapping_agreement_summaries"])
        self.assertIn("primitive=one_off_false_positive", agreement_text)
        self.assertIn("agreement=1/3", agreement_text)
        self.assertIn("accepted=False", agreement_text)

