    def test_wrong_subject_normal_historical_audit_statement_is_not_score_eligible(self):
        document, anchor, raw = _audit_fixture()
        claim = AdjudicatedClaim.from_raw(
            raw=raw,
            document=document,
            anchor=anchor,
            subject_entity_id="CORP_SUPPLIER",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SUPPLIER,
            directness=Directness.INDIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.SUPPLIER,
            polarity=Polarity.NORMAL,
            temporal_status=TemporalStatus.HISTORICAL,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2020, 3, 18),
        )
        mapping = PrimitiveMappingProposal.build(
            claim_id=claim.claim_id,
            archetype_id="R13_CROSS_ARCHETYPE_ACCOUNTING_TRUST_PRICE_VALIDATION",
            primitive_id="accounting_trust_break",
            support_direction=SupportDirection.NEUTRAL,
            mapping_status=MappingStatus.REJECTED,
            rationale="The audit statement belongs to the supplier, not the target.",
        )

        eligibility = derive_score_eligibility(
            document=document,
            anchor=anchor,
            claim=claim,
            mapping=mapping,
            as_of_date=date(2026, 6, 21),
        )

        self.assertFalse(eligibility.eligible)
        self.assertIn("target_scope_not_allowed:SUPPLIER", eligibility.reasons)
        self.assertIn("target_not_direct:INDIRECT", eligibility.reasons)
        self.assertIn("temporal_not_allowed:HISTORICAL", eligibility.reasons)
        self.assertIn("mapping_not_accepted:REJECTED", eligibility.reasons)

    def test_subsidiary_and_parent_claims_are_not_default_score_eligible_for_target(self):
        document, anchor, raw = _current_target_risk_fixture()
        contract = EvidenceContractV2(
            archetype_id="R13_CROSS_ARCHETYPE_ACCOUNTING_TRUST_PRICE_VALIDATION",
            required_primitives=("accounting_trust_break",),
            green_gate=GateExpression.primitive("accounting_trust_break"),
        )

        for relation, scope, subject_entity_id in (
            (RelationToTarget.SUBSIDIARY, TargetScopeStatus.SUBSIDIARY, "CORP_TARGET_SUB"),
            (RelationToTarget.PARENT, TargetScopeStatus.PARENT, "CORP_TARGET_PARENT"),
        ):
            with self.subTest(scope=scope.value):
                claim = AdjudicatedClaim.from_raw(
                    raw=raw,
                    document=document,
                    anchor=anchor,
                    subject_entity_id=subject_entity_id,
                    target_entity_id="CORP_TARGET",
                    relation_to_target=relation,
                    directness=Directness.DIRECT,
                    verification_status=VerificationStatus.SEMANTIC_VERIFIED,
                    target_scope_status=scope,
                    polarity=Polarity.NEGATIVE,
                    temporal_status=TemporalStatus.CURRENT,
                    semantic_status=SemanticStatus.PASS_,
                    investigation_status=InvestigationStatus.COMPLETE,
                    event_date=date(2026, 6, 1),
                )
                mapping = PrimitiveMappingProposal.build(
                    claim_id=claim.claim_id,
                    archetype_id=contract.archetype_id,
                    primitive_id="accounting_trust_break",
                    support_direction=SupportDirection.SUPPORT,
                    mapping_status=MappingStatus.ACCEPTED,
                    rationale="Related-entity accounting risk should not be target score evidence by default.",
                )
                eligibility = derive_score_eligibility(
                    document=document,
                    anchor=anchor,
                    claim=claim,
                    mapping=mapping,
                    as_of_date=date(2026, 6, 21),
                )
                ledger = AppendOnlyEvidenceLedger()
                ledger.append_claim(claim)
                ledger.append_mapping(mapping)
                states = aggregate_primitive_states(
                    ledger=ledger,
                    contract=contract,
                    as_of_date=date(2026, 6, 21),
                )

                self.assertFalse(eligibility.eligible)
                self.assertIn(f"target_scope_not_allowed:{scope.value}", eligibility.reasons)
                self.assertNotIn("target_not_direct:DIRECT", eligibility.reasons)
                self.assertEqual(states["accounting_trust_break"].status, PrimitiveStatus.UNKNOWN)
                self.assertEqual(states["accounting_trust_break"].support_claim_ids, ())

