    def test_current_fetch_status_manifest_keeps_current_text_as_asof_unverified(self):
        manifest = build_current_fetch_status_manifest(
            fixture_seed_manifest={
                "schema_version": "e2r_source_backed_fixture_seed_manifest_v1",
                "seeds": [
                    {
                        "archetype_id": "C06_HBM_MEMORY_CUSTOMER_CAPACITY",
                        "candidate_id": "RPLAY-C06",
                        "fixture_seed_id": "FSEED-OK",
                        "source_anchor": "https://example.com/hbm",
                        "as_of_date": "2025-03-01",
                        "snapshot_request_ready": True,
                    },
                    {
                        "archetype_id": "C06_HBM_MEMORY_CUSTOMER_CAPACITY",
                        "candidate_id": "RPLAY-C06",
                        "fixture_seed_id": "FSEED-FAIL",
                        "source_anchor": "https://example.com/fail",
                        "as_of_date": "2025-03-01",
                        "snapshot_request_ready": True,
                    },
                    {
                        "archetype_id": "C06_HBM_MEMORY_CUSTOMER_CAPACITY",
                        "candidate_id": "RPLAY-C06",
                        "fixture_seed_id": "FSEED-NO-TRY",
                        "source_anchor": "https://example.com/no-try",
                        "as_of_date": "2025-03-01",
                        "snapshot_request_ready": True,
                    },
                ],
            },
            fetch_rows=(
                {
                    "fixture_seed_id": "FSEED-OK",
                    "ok": True,
                    "current_text_path": "output/current/hbm.txt",
                    "current_text_hash": "HASH-HBM",
                    "current_text_chars": 1234,
                    "fetched_at": "2026-06-26T05:00:00",
                    "content_type": "text/html",
                },
                {
                    "fixture_seed_id": "FSEED-FAIL",
                    "ok": False,
                    "reason": "HTTPError:404",
                    "fetched_at": "2026-06-26T05:00:01",
                },
            ),
        )

        self.assertEqual(manifest["summary"]["fixture_seed_count"], 3)
        self.assertEqual(manifest["summary"]["current_fetch_text_available_count"], 1)
        self.assertEqual(manifest["summary"]["current_fetch_failed_count"], 1)
        self.assertEqual(manifest["summary"]["current_fetch_not_attempted_count"], 1)
        self.assertEqual(manifest["summary"]["asof_snapshot_verified_count"], 0)
        self.assertEqual(manifest["summary"]["evidence_document_fixture_ready_count"], 0)
        self.assertEqual(manifest["summary"]["production_score_fixture_count"], 0)
        by_seed = {row["fixture_seed_id"]: row for row in manifest["rows"]}
        self.assertEqual(by_seed["FSEED-OK"]["current_fetch_status"], "current_fetch_text_available_asof_unverified")
        self.assertFalse(by_seed["FSEED-OK"]["asof_snapshot_verified"])
        self.assertFalse(by_seed["FSEED-OK"]["evidence_document_fixture_ready"])
        self.assertFalse(by_seed["FSEED-OK"]["production_score_fixture"])
        self.assertEqual(by_seed["FSEED-FAIL"]["current_fetch_status"], "current_fetch_failed")
        self.assertEqual(by_seed["FSEED-NO-TRY"]["current_fetch_status"], "current_fetch_not_attempted")

    def test_snapshot_remediation_plan_classifies_current_fetch_and_failure_modes(self):
        plan = build_snapshot_remediation_plan(
            current_fetch_status_manifest={
                "schema_version": "e2r_current_fetch_status_manifest_v1",
                "rows": [
                    {
                        "fixture_seed_id": "FSEED-OK",
                        "candidate_id": "RPLAY-OK",
                        "archetype_id": "C06_HBM_MEMORY_CUSTOMER_CAPACITY",
                        "source_anchor": "https://example.com/hbm",
                        "as_of_date": "2025-03-01",
                        "current_fetch_status": "current_fetch_text_available_asof_unverified",
                    },
                    {
                        "fixture_seed_id": "FSEED-PDF",
                        "candidate_id": "RPLAY-PDF",
                        "archetype_id": "C08_SEMI_TEST_SOCKET_CUSTOMER_QUALITY",
                        "source_anchor": "https://example.com/report.pdf",
                        "as_of_date": "2025-03-01",
                        "current_fetch_status": "current_fetch_failed",
                        "reason": "live_pdf_text_extraction_failed:pypdf extraction failed",
                    },
                    {
                        "fixture_seed_id": "FSEED-403",
                        "candidate_id": "RPLAY-403",
                        "archetype_id": "C03_DEFENSE_EXPORT_FRAMEWORK_BACKLOG",
                        "source_anchor": "https://www.reuters.com/world/example",
                        "as_of_date": "2025-03-01",
                        "current_fetch_status": "current_fetch_failed",
                        "reason": "live_fetch_failed:HTTPError:HTTP Error 403: Forbidden",
                    },
                    {
                        "fixture_seed_id": "FSEED-404",
                        "candidate_id": "RPLAY-404",
                        "archetype_id": "C01_ORDER_BACKLOG_MARGIN_BRIDGE",
                        "source_anchor": "https://example.com/dead",
                        "as_of_date": "2025-03-01",
                        "current_fetch_status": "current_fetch_failed",
                        "reason": "live_fetch_failed:HTTPError:HTTP Error 404: Not Found",
                    },
                    {
                        "fixture_seed_id": "FSEED-TRANSPORT",
                        "candidate_id": "RPLAY-TRANSPORT",
                        "archetype_id": "C16_STRATEGIC_RESOURCE_POLICY_SUPPLY",
                        "source_anchor": "https://example.com/reset",
                        "as_of_date": "2025-03-01",
                        "current_fetch_status": "current_fetch_failed",
                        "reason": "live_fetch_failed:RemoteDisconnected:Remote end closed connection without response",
                    },
                ],
            }
        )

        self.assertEqual(plan["summary"]["task_count"], 5)
        self.assertEqual(plan["summary"]["score_blocked_task_count"], 5)
        self.assertEqual(plan["summary"]["asof_verify_current_text_count"], 1)
        self.assertEqual(plan["summary"]["pdf_parser_repair_count"], 1)
        self.assertEqual(plan["summary"]["archive_or_alternative_source_count"], 1)
        self.assertEqual(plan["summary"]["dead_url_replacement_count"], 1)
        self.assertEqual(plan["summary"]["retry_current_fetch_count"], 1)
        by_seed = {task["fixture_seed_id"]: task for task in plan["tasks"]}
        self.assertEqual(by_seed["FSEED-OK"]["remediation_type"], "verify_current_text_asof_identity")
        self.assertEqual(by_seed["FSEED-PDF"]["remediation_type"], "pdf_parser_repair")
        self.assertEqual(by_seed["FSEED-403"]["remediation_type"], "archive_or_alternative_source")
        self.assertEqual(by_seed["FSEED-404"]["remediation_type"], "dead_url_replacement")
        self.assertEqual(by_seed["FSEED-TRANSPORT"]["remediation_type"], "retry_current_fetch_with_browser_or_tls_repair")
        self.assertTrue(all(task["score_blocked_until_resolved"] for task in plan["tasks"]))

