        self.assertEqual(fixtures["summary"]["evidence_document_fixture_ready_count"], 1)
        self.assertEqual(fixtures["summary"]["production_score_fixture_count"], 0)
        self.assertEqual(claim_tasks["summary"]["task_count"], 1)
        self.assertEqual(claim_tasks["summary"]["contract_blind_task_count"], 1)
        self.assertEqual(claim_tasks["summary"]["score_blocked_task_count"], 1)
        self.assertEqual(claim_tasks["summary"]["production_score_fixture_count"], 0)
        task = claim_tasks["tasks"][0]
        self.assertEqual(task["target_entity_id"], "CORP_TARGET")
        self.assertEqual(task["target_names"], ["Target issuer", "005930"])
        self.assertTrue(task["contract_blind_extraction"])
        self.assertIn("current_score", task["forbidden_context_excluded"])
        self.assertNotIn("score", task)

