        self.assertEqual(manifest["summary"]["task_count"], 4)
        self.assertEqual(manifest["summary"]["raw_assertions_extracted_count"], 1)
        self.assertEqual(manifest["summary"]["claim_replay_not_attempted_count"], 1)
        self.assertEqual(manifest["summary"]["raw_assertion_anchor_mismatch_count"], 1)
        self.assertEqual(manifest["summary"]["invalid_provider_output_count"], 1)
        self.assertEqual(manifest["summary"]["adjudication_ready_count"], 1)
        self.assertEqual(manifest["summary"]["score_blocked_result_count"], 4)
