        self.assertEqual(by_task["CLREPLAY-MISMATCH"]["replay_status"], "raw_assertion_anchor_mismatch")
        self.assertEqual(by_task["CLREPLAY-FORBIDDEN"]["replay_status"], "invalid_provider_output")

