    def test_stage_court_manifest_keeps_high_score_yellow_when_green_primitive_missing(self):
        contract = EvidenceContractV2(
            archetype_id="C06_HBM_MEMORY_CUSTOMER_CAPACITY",
            required_primitives=("customer_allocation", "cash_or_revision_conversion"),
            green_gate=GateExpression.all(
                (
                    GateExpression.primitive("customer_allocation"),
                    GateExpression.primitive("cash_or_revision_conversion"),
                )
            ),
        )
        score_snapshot_results = {
            "schema_version": "e2r_score_snapshot_result_manifest_v1",
            "results": [
                {
                    "task_id": "SSRES-C06",
                    "score_snapshot_task_id": "SSNAP-C06",
                    "fixture_seed_id": "FSEED-C06",
                    "candidate_id": "RPLAY-C06",
                    "archetype_id": "C06_HBM_MEMORY_CUSTOMER_CAPACITY",
                    "target_entity_id": "CORP_TARGET",
                    "result_status": "score_snapshot_ready",
                    "score_interval_ready": True,
                    "verified_score": 92.0,
                    "potential_score_upper_bound": 92.0,
                    "contribution_ids": ["SCON-CUSTOMER"],
                    "support_claim_ids": ["CLM-CUSTOMER"],
                    "component_keys": ["earnings_visibility"],
                }
            ],
        }
        contribution_results = {
            "schema_version": "e2r_score_contribution_result_manifest_v1",
            "results": [
                {
                    "task_id": "SCRES-CUSTOMER",
                    "result_status": "score_contribution_ready",
                    "score_contribution_ready": True,
                    "contribution_id": "SCON-CUSTOMER",
                    "primitive_id": "customer_allocation",
                    "raw_points": 92.0,
                    "support_claim_ids": ["CLM-CUSTOMER"],
                    "source_family_ids": ["SFAM-CUSTOMER"],
                }
            ],
        }

        tasks = build_stage_court_task_manifest(
            score_snapshot_result_manifest=score_snapshot_results,
            score_contribution_result_manifest=contribution_results,
            contracts_by_archetype={"C06_HBM_MEMORY_CUSTOMER_CAPACITY": contract},
        )
        results = build_stage_court_result_manifest(
            stage_court_task_manifest=tasks,
            score_contribution_result_manifest=contribution_results,
            contracts_by_archetype={"C06_HBM_MEMORY_CUSTOMER_CAPACITY": contract},
        )

        self.assertEqual(tasks["summary"]["task_count"], 1)
        self.assertEqual(tasks["summary"]["production_stage_fixture_count"], 0)
        task = tasks["tasks"][0]
        self.assertEqual(task["present_primitive_ids"], ("customer_allocation",))
        self.assertTrue(task["score_blocked_until_stage_court_result"])
        self.assertFalse(task["production_stage_fixture"])
        self.assertEqual(results["summary"]["stage_court_ready_count"], 1)
        self.assertEqual(results["summary"]["production_stage_fixture_count"], 0)
        result = results["results"][0]
        self.assertEqual(result["result_status"], "stage_court_ready")
        self.assertEqual(result["canonical_stage"], "3-Yellow")
        self.assertEqual(result["investigation_status"], "PENDING")
        self.assertEqual(result["score_status"], "FINAL")
        self.assertEqual(result["missing_green_primitives"], ("cash_or_revision_conversion",))
        self.assertFalse(result["production_stage_fixture"])

    def test_claim_replay_chain_audit_keeps_stage_preview_out_of_production_cutover(self):
        empty = {"schema_version": "empty", "summary": {}}
        stage_ready = {
            "schema_version": "e2r_stage_court_result_manifest_v1",
            "summary": {
                "task_count": 1,
                "stage_court_ready_count": 1,
                "production_score_fixture_count": 0,
                "production_stage_fixture_count": 0,
            },
        }

        audit = build_claim_replay_chain_audit_manifest(
            claim_replay_result_manifest={
                "schema_version": "claim",
                "summary": {"task_count": 1, "adjudication_ready_count": 1},
            },
            adjudication_result_manifest={
                "schema_version": "adj",
                "summary": {"task_count": 1, "mapping_ready_count": 1},
            },
            primitive_mapping_result_manifest={
                "schema_version": "map",
                "summary": {"result_count": 1, "eligibility_ready_count": 1},
            },
            eligibility_result_manifest={
                "schema_version": "elig",
                "summary": {"task_count": 1, "score_contribution_ready_count": 1},
            },
            score_contribution_result_manifest={
                "schema_version": "score_contrib",
                "summary": {"task_count": 1, "score_contribution_ready_count": 1},
            },
            score_snapshot_result_manifest={
                "schema_version": "score_snapshot",
                "summary": {"task_count": 1, "score_interval_ready_count": 1},
            },
            stage_court_result_manifest=stage_ready,
        )
        blocked = build_claim_replay_chain_audit_manifest(
            claim_replay_result_manifest=empty,
            adjudication_result_manifest=empty,
            primitive_mapping_result_manifest=empty,
            eligibility_result_manifest=empty,
            score_contribution_result_manifest=empty,
            score_snapshot_result_manifest=empty,
            stage_court_result_manifest={
                "schema_version": "stage",
                "summary": {"stage_court_ready_count": 0},
            },
        )
        invalid = build_claim_replay_chain_audit_manifest(
            claim_replay_result_manifest=empty,
            adjudication_result_manifest=empty,
            primitive_mapping_result_manifest=empty,
            eligibility_result_manifest=empty,
            score_contribution_result_manifest=empty,
            score_snapshot_result_manifest=empty,
            stage_court_result_manifest={
                "schema_version": "stage",
                "summary": {
                    "stage_court_ready_count": 1,
                    "production_stage_fixture_count": 1,
                },
            },
        )

        self.assertEqual(audit["summary"]["chain_status"], "stage_preview_ready_not_production_cutover")
        self.assertTrue(audit["summary"]["evidence_os_chain_ready"])
        self.assertFalse(audit["summary"]["production_cutover_ready"])
        self.assertEqual(audit["summary"]["first_blocking_stage"], "production_cutover_acceptance")
        self.assertEqual(
            audit["summary"]["first_blocking_reason"],
            "production_cutover_requires_full_replay_acceptance",
        )
        self.assertEqual(audit["summary"]["stage_court_ready_count"], 1)
        self.assertEqual(audit["summary"]["production_stage_fixture_total"], 0)
        self.assertEqual(blocked["summary"]["chain_status"], "blocked_no_stage_court_ready_results")
        self.assertFalse(blocked["summary"]["evidence_os_chain_ready"])
        self.assertEqual(blocked["summary"]["blocked_reason"], "no_stage_court_ready_results")
        self.assertEqual(blocked["summary"]["first_blocking_stage"], "claim_replay")
        self.assertEqual(blocked["summary"]["first_blocking_reason"], "no_claim_replay_tasks")
        self.assertEqual(invalid["summary"]["chain_status"], "invalid_production_fixture_present")
        self.assertFalse(invalid["summary"]["evidence_os_chain_ready"])
        self.assertEqual(invalid["summary"]["production_stage_fixture_total"], 1)
        self.assertEqual(invalid["summary"]["first_blocking_stage"], "production_cutover_guard")

