            class _Provider:
                def __init__(self):
                    self.batch_archetypes = []
                    self.primitive_ids_by_batch = []

                def map_many(self, inputs):
                    self.batch_archetypes.append(tuple(item.contract.archetype_id for item in inputs))
                    self.primitive_ids_by_batch.append(tuple(inputs[0].canonical_primitive_ids))
                    return PrimitiveMappingOutput(
                        tuple(
                            PrimitiveMappingProposal.build(
                                claim_id=item.claim.claim_id,
                                archetype_id=item.contract.archetype_id,
                                primitive_id=item.canonical_primitive_ids[0],
                                support_direction=SupportDirection.SUPPORT,
                                mapping_status=MappingStatus.ACCEPTED,
                                rationale="provider mapped test claim",
                            )
                            for item in inputs
                        )
                    )

            provider = _Provider()
            with patch.object(
                primitive_mapping_cli,
                "build_default_codex_agentic_evidence_provider_bundle",
                return_value=SimpleNamespace(mapper=provider),
            ):
                provider_paths = primitive_mapping_cli.run_primitive_mapping(
                    primitive_mapping_task_manifest_path=task_path,
                    output_directory=tmp / "provider",
                    output_prefix="fixture",
                    run_provider=True,
                    batch_size=8,
                )

            provider_run = json.loads(provider_paths["run_manifest_json"].read_text(encoding="utf-8"))
            provider_results = json.loads(provider_paths["primitive_mapping_results_json"].read_text(encoding="utf-8"))
            eligibility_tasks = json.loads(provider_paths["eligibility_tasks_json"].read_text(encoding="utf-8"))

            self.assertEqual(provider.batch_archetypes, [
                ("C01_ORDER_BACKLOG_MARGIN_BRIDGE",),
                ("C03_DEFENSE_EXPORT_FRAMEWORK_BACKLOG",),
            ])
            self.assertNotIn("eps_fcf_explosion", provider.primitive_ids_by_batch[0])
