            self.assertEqual(provider_results["summary"]["eligibility_ready_count"], 2)
            self.assertEqual(provider_results["summary"]["production_score_fixture_count"], 0)
            self.assertEqual(eligibility_tasks["summary"]["task_count"], 2)
            self.assertEqual(eligibility_tasks["summary"]["production_score_fixture_count"], 0)

