    def test_replay_gap_plan_uses_post_chain_results_to_avoid_repeating_extraction(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            tmp = Path(tmpdir)
            replay_acceptance = {
                "schema_version": "e2r_replay_acceptance_manifest_v1",
                "summary": {
                    "stage_preview_ready_count": 0,
                    "unsupported_source_gap_count": 2,
                    "production_cutover_ready": False,
                },
                "rows": [
                    {
                        "archetype_id": "C01_ORDER_BACKLOG_MARGIN_BRIDGE",
                        "coverage_status": "unsupported_source_gap",
                        "contract_present": True,
                    },
                    {
                        "archetype_id": "C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE",
                        "coverage_status": "unsupported_source_gap",
                        "contract_present": True,
                    },
                ],
            }
            claim_tasks = {
                "schema_version": "e2r_claim_replay_task_manifest_v1",
                "tasks": [
                    {
                        "archetype_id": "C01_ORDER_BACKLOG_MARGIN_BRIDGE",
                        "task_id": "CLREPLAY-C01",
                        "contract_blind_extraction": True,
                        "production_score_fixture": False,
                    },
                    {
                        "archetype_id": "C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE",
                        "task_id": "CLREPLAY-C26",
                        "contract_blind_extraction": True,
                        "production_score_fixture": False,
                    },
                ],
            }
            claim_results = {
                "schema_version": "e2r_claim_replay_result_manifest_v1",
                "results": [
                    {
                        "archetype_id": "C01_ORDER_BACKLOG_MARGIN_BRIDGE",
                        "task_id": "CLREPLAY-C01",
                        "raw_assertions": [],
                    },
                    {
                        "archetype_id": "C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE",
                        "task_id": "CLREPLAY-C26",
                        "raw_assertions": [{"raw_assertion_id": "RAW-C26"}],
                    },
                ],
            }
            adjudication_results = {
                "schema_version": "e2r_adjudication_result_manifest_v1",
                "results": [
                    {
                        "archetype_id": "C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE",
                        "mapping_ready": True,
                        "target_scope_status": "DIRECT",
                        "temporal_status": "CURRENT",
                        "semantic_status": "PASS",
                    },
                ],
            }
            mapping_results = {
                "schema_version": "e2r_primitive_mapping_result_manifest_v1",
                "results": [
                    {
                        "archetype_id": "C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE",
                        "mapping_status": "REJECTED",
                        "eligibility_ready": False,
                    },
                    {
                        "archetype_id": "C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE",
                        "mapping_status": "REJECTED",
                        "eligibility_ready": False,
                    },
                ],
            }
            paths = {}
            for name, manifest in (
                ("replay", replay_acceptance),
                ("claim_tasks", claim_tasks),
                ("claim_results", claim_results),
                ("adjudication", adjudication_results),
                ("mapping", mapping_results),
            ):
                path = tmp / f"{name}.json"
                path.write_text(json.dumps(manifest, ensure_ascii=False), encoding="utf-8")
                paths[name] = path

            output_paths = replay_gap_plan_cli.run_replay_gap_plan(
                replay_acceptance_manifest_path=paths["replay"],
                claim_replay_task_manifest_path=paths["claim_tasks"],
                claim_replay_result_manifest_path=paths["claim_results"],
                adjudication_result_manifest_path=paths["adjudication"],
                primitive_mapping_result_manifest_path=paths["mapping"],
                output_directory=tmp / "out",
                output_prefix="fixture",
            )
            manifest = json.loads(output_paths["gap_plan_json"].read_text(encoding="utf-8"))
            by_archetype = {task["archetype_id"]: task for task in manifest["tasks"]}

            self.assertEqual(manifest["summary"]["post_chain_no_raw_assertion_gap_task_count"], 1)
            self.assertEqual(manifest["summary"]["post_chain_mapping_rejected_gap_task_count"], 1)
            self.assertEqual(
                by_archetype["C01_ORDER_BACKLOG_MARGIN_BRIDGE"]["post_chain_gap_stage"],
                "claim_replay_executed_no_raw_assertions",
            )
            self.assertEqual(
                by_archetype["C01_ORDER_BACKLOG_MARGIN_BRIDGE"]["post_chain_next_action"],
                "find_replacement_source_with_direct_target_assertion",
            )
            self.assertEqual(
                by_archetype["C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE"]["source_gap_stage"],
                "claim_replay_task_ready",
            )
            self.assertEqual(
                by_archetype["C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE"]["post_chain_gap_stage"],
                "primitive_mapping_all_rejected",
            )
            self.assertEqual(
                by_archetype["C26_PLATFORM_AD_REVENUE_OPERATING_LEVERAGE"]["post_chain_next_action"],
                "find_source_with_required_primitives_or_review_contract_mapping_rationale",
            )

    def test_adversarial_acceptance_cli_maps_all_24_cases_to_evidence_os_path(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            tmp = Path(tmpdir)
            chain_audit = {
                "schema_version": "e2r_claim_replay_chain_audit_manifest_v1",
                "summary": {
                    "chain_status": "stage_preview_ready_not_production_cutover",
                    "evidence_os_chain_ready": True,
                    "production_cutover_ready": False,
                    "stage_court_ready_count": 2,
                    "production_score_fixture_total": 0,
                    "production_stage_fixture_total": 0,
                },
            }
            replay_acceptance = {
                "schema_version": "e2r_replay_acceptance_manifest_v1",
                "summary": {
                    "stage_preview_ready_count": 2,
                    "unsupported_source_gap_count": 34,
                    "production_cutover_ready": False,
                },
            }
            chain_path = tmp / "chain.json"
            replay_path = tmp / "replay.json"
            chain_path.write_text(json.dumps(chain_audit, ensure_ascii=False), encoding="utf-8")
            replay_path.write_text(json.dumps(replay_acceptance, ensure_ascii=False), encoding="utf-8")

            paths = adversarial_acceptance_cli.run_adversarial_acceptance(
                chain_audit_manifest_path=chain_path,
                replay_acceptance_manifest_path=replay_path,
                tests_root=Path(__file__).resolve().parent,
                output_directory=tmp / "out",
                output_prefix="fixture",
            )
            manifest = json.loads(paths["acceptance_json"].read_text(encoding="utf-8"))
            by_case = {row["case_id"]: row for row in manifest["rows"]}

            self.assertEqual(manifest["summary"]["case_count"], 24)
            self.assertEqual(manifest["summary"]["named_regression_covered_count"], 24)
            self.assertEqual(manifest["summary"]["missing_representative_test_count"], 0)
            self.assertTrue(manifest["summary"]["all_cases_linked_to_cli_path"])
            self.assertFalse(manifest["summary"]["production_cutover_ready"])
            self.assertEqual(
                manifest["summary"]["adversarial_acceptance_status"],
                "covered_by_named_regression_pending_chain_or_replay_acceptance",
            )
            self.assertFalse(manifest["summary"]["adversarial_acceptance_ready"])
            self.assertEqual(manifest["summary"]["replay_stage_preview_ready_count"], 2)
            self.assertEqual(manifest["summary"]["replay_unsupported_source_gap_count"], 34)
            self.assertEqual(
                by_case["14_twenty_reuters_reposts"]["evidence_os_stages"],
                ["source_lineage_dedupe", "primitive_aggregation", "score_contribution"],
            )
            self.assertIn(
                "run_agentic_primitive_aggregation",
                by_case["14_twenty_reuters_reposts"]["cli_path_segments"],
            )
            self.assertIn("claim_extraction", by_case["24_prompt_injection_document"]["evidence_os_stages"])
            self.assertIn(
                "run_agentic_claim_extraction",
                by_case["24_prompt_injection_document"]["cli_path_segments"],
            )
            self.assertTrue(
                all(not row["production_score_fixture"] and not row["production_stage_fixture"] for row in by_case.values())
            )

