    def test_frozen_repeatability_acceptance_requires_score_stage_fingerprints(self):
        replay_report = {
            "target_entity_id": "KR:000660",
            "archetype_id": "C06_HBM_MEMORY_CUSTOMER_CAPACITY",
            "as_of_date": "2024-04-25",
            "document_id": "DOC-SK-HYNIX",
            "anchor_id": "ANCH-SK-HYNIX",
            "successful_run_count": 3,
            "variance_after_source_assertion_and_duplicate_dedupe": {
                "run_count": 3,
                "stable": False,
                "score_relevant_stable": True,
                "stable_axes": {
                    "accepted_primitives": True,
                    "score_relevant_source_primitives": True,
                },
                "unstable_axes": ("claim_ids", "mapping_ids"),
            },
            "runs": (
                {"run_index": 0, "ok": True},
                {"run_index": 1, "ok": True},
                {"run_index": 2, "ok": True},
            ),
        }

        manifest = frozen_repeatability_cli.build_frozen_repeatability_acceptance_manifest(
            replay_reports=(replay_report,),
        )

        self.assertFalse(manifest["summary"]["frozen_repeatability_acceptance_ready"])
        self.assertEqual(manifest["summary"]["score_relevant_repeatability_ready_count"], 1)
        self.assertEqual(manifest["summary"]["score_stage_repeatability_ready_count"], 0)
        self.assertEqual(manifest["rows"][0]["acceptance_status"], "repeatability_not_ready")
        self.assertEqual(
            manifest["blockers"][0]["blocker_id"],
            "frozen_repeatability_score_stage_fingerprint_missing",
        )

        ready_manifest = frozen_repeatability_cli.build_frozen_repeatability_acceptance_manifest(
            replay_reports=(
                {
                    **replay_report,
                    "runs": (
                        {"run_index": 0, "ok": True, "verified_score": 12.5, "stage": "3-Yellow"},
                        {"run_index": 1, "ok": True, "verified_score": 12.5, "stage": "3-Yellow"},
                        {"run_index": 2, "ok": True, "verified_score": 12.5, "stage": "3-Yellow"},
                    ),
                },
            ),
        )
        self.assertTrue(ready_manifest["summary"]["frozen_repeatability_acceptance_ready"])
        self.assertEqual(ready_manifest["rows"][0]["acceptance_status"], "repeatability_ready")

