    def test_replacement_snapshot_verification_requires_same_event_and_asof_proof(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            tmp = Path(tmpdir)
            ok_text = tmp / "ok.txt"
            future_text = tmp / "future.txt"
            missing_text = tmp / "missing.txt"
            ok_text.write_text("Published 2025-02-28. Same event candidate text.", encoding="utf-8")
            future_text.write_text("Published 2025-03-02. Future candidate text.", encoding="utf-8")
            missing_text.write_text("Published 2025-02-28. Missing verification text.", encoding="utf-8")
            ok_hash = hashlib.sha256(ok_text.read_text(encoding="utf-8").encode("utf-8")).hexdigest()
            future_hash = hashlib.sha256(future_text.read_text(encoding="utf-8").encode("utf-8")).hexdigest()
            missing_hash = hashlib.sha256(missing_text.read_text(encoding="utf-8").encode("utf-8")).hexdigest()

            fetch_status_manifest = {
                "schema_version": "e2r_replacement_candidate_fetch_status_manifest_v1",
                "rows": [
                    {
                        "task_id": "RCACQ-OK",
                        "replacement_candidate_id": "SRCAND-OK",
                        "request_id": "SREPL-OK",
                        "fixture_seed_id": "FSEED-OK",
                        "candidate_id": "RPLAY-OK",
                        "archetype_id": "C01_ORDER_BACKLOG_MARGIN_BRIDGE",
                        "original_source_anchor": "https://example.com/original",
                        "candidate_url": "https://alt.example.com/same-event",
                        "as_of_date": "2025-03-01",
                        "fetch_status": "replacement_candidate_current_text_available_replacement_unverified",
                        "current_text_path": str(ok_text),
                        "current_text_hash": ok_hash,
                        "current_text_chars": ok_text.stat().st_size,
                    },
                    {
                        "task_id": "RCACQ-MISSING",
                        "replacement_candidate_id": "SRCAND-MISSING",
                        "request_id": "SREPL-MISSING",
                        "fixture_seed_id": "FSEED-MISSING",
                        "candidate_id": "RPLAY-MISSING",
                        "archetype_id": "C03_DEFENSE_EXPORT_FRAMEWORK_BACKLOG",
                        "original_source_anchor": "https://example.com/original-missing",
                        "candidate_url": "https://alt.example.com/missing",
                        "as_of_date": "2025-03-01",
                        "fetch_status": "replacement_candidate_current_text_available_replacement_unverified",
                        "current_text_path": str(missing_text),
                        "current_text_hash": missing_hash,
                        "current_text_chars": missing_text.stat().st_size,
                    },
                    {
                        "task_id": "RCACQ-FUTURE",
                        "replacement_candidate_id": "SRCAND-FUTURE",
                        "request_id": "SREPL-FUTURE",
                        "fixture_seed_id": "FSEED-FUTURE",
                        "candidate_id": "RPLAY-FUTURE",
                        "archetype_id": "C04_NUCLEAR_POLICY_PROJECT_LEGAL_DELAY",
                        "original_source_anchor": "https://example.com/original-future",
                        "candidate_url": "https://alt.example.com/future",
                        "as_of_date": "2025-03-01",
                        "fetch_status": "replacement_candidate_current_text_available_replacement_unverified",
                        "current_text_path": str(future_text),
                        "current_text_hash": future_hash,
                        "current_text_chars": future_text.stat().st_size,
                    },
                    {
                        "task_id": "RCACQ-NOTREADY",
                        "replacement_candidate_id": "SRCAND-NOTREADY",
                        "request_id": "SREPL-NOTREADY",
                        "fixture_seed_id": "FSEED-NOTREADY",
                        "candidate_id": "RPLAY-NOTREADY",
                        "archetype_id": "C06_HBM_MEMORY_CUSTOMER_CAPACITY",
                        "original_source_anchor": "https://example.com/original-notready",
                        "candidate_url": "https://alt.example.com/notready",
                        "as_of_date": "2025-03-01",
                        "fetch_status": "replacement_candidate_fetch_failed",
                    },
                ],
            }

            manifest = build_replacement_snapshot_verification_manifest(
                fetch_status_manifest=fetch_status_manifest,
                verification_rows=[
                    {
                        "task_id": "RCACQ-OK",
                        "ok": True,
                        "source_replacement_verified": True,
                        "snapshot_url": "https://alt.example.com/same-event",
                        "snapshot_as_of_date": "2025-02-28",
                        "snapshot_source_type": "news_article",
                    },
                    {
                        "task_id": "RCACQ-FUTURE",
                        "ok": True,
                        "source_replacement_verified": True,
                        "snapshot_url": "https://alt.example.com/future",
                        "snapshot_as_of_date": "2025-03-02",
                    },
                ],
            )

        self.assertEqual(manifest["summary"]["row_count"], 4)
        self.assertEqual(manifest["summary"]["replacement_snapshot_verified_count"], 1)
        self.assertEqual(manifest["summary"]["same_event_verification_missing_count"], 1)
        self.assertEqual(manifest["summary"]["future_snapshot_not_allowed_count"], 1)
        self.assertEqual(manifest["summary"]["fetch_not_ready_count"], 1)
        self.assertEqual(manifest["summary"]["source_replacement_verified_count"], 2)
        self.assertEqual(manifest["summary"]["asof_snapshot_verified_count"], 1)
        self.assertEqual(manifest["summary"]["evidence_document_fixture_ready_count"], 1)
        self.assertEqual(manifest["summary"]["production_score_fixture_count"], 0)

        by_task = {row["task_id"]: row for row in manifest["rows"]}
        self.assertEqual(by_task["RCACQ-OK"]["verification_status"], "replacement_snapshot_verified")
        self.assertTrue(by_task["RCACQ-OK"]["asof_snapshot_verified"])
        self.assertTrue(by_task["RCACQ-OK"]["evidence_document_fixture_ready"])
        self.assertFalse(by_task["RCACQ-OK"]["production_score_fixture"])
        self.assertEqual(by_task["RCACQ-MISSING"]["verification_status"], "same_event_verification_missing")
        self.assertEqual(by_task["RCACQ-FUTURE"]["verification_status"], "future_snapshot_not_allowed")
        self.assertEqual(by_task["RCACQ-NOTREADY"]["verification_status"], "fetch_not_ready")

