        self.assertEqual(ready["source_type"], SourceType.NEWS.value)
        self.assertTrue(ready["anchor_verified"])
        self.assertTrue(ready["evidence_document_fixture_ready"])
        self.assertFalse(ready["claim_replay_ready"])
        self.assertFalse(ready["production_score_fixture"])
