    def test_claim_extraction_anchor_text_prefers_target_alias_window(self):
        from e2r.cli.run_agentic_claim_extraction import _fixture_anchor_text

        text = (
            "Introductory market background. " * 80
            + "The South Korean consortium includes KEPCO E&C, KEPCO Nuclear Fuel, KEPCO KPS, "
            + "Doosan Enerbility Co. and Daewoo Engineering & Construction Co."
        )

        anchor = _fixture_anchor_text(text, max_chars=300, target_names=("KEPCO KPS",))

        self.assertIn("KEPCO KPS", anchor)
        self.assertIn("South Korean consortium", anchor)
        self.assertLessEqual(len(anchor), 340)

    def test_claim_extraction_anchor_text_prefers_operating_signal_over_target_boilerplate(self):
        from e2r.cli.run_agentic_claim_extraction import _fixture_anchor_text

        text = (
            "SK hynix Inc. accessibility statement skip navigation resources client login. "
            * 20
            + "Revenue rose as demand for AI server memory increased rapidly, "
            + "with premium products such as HBM3 and DDR5 driving higher sales and DRAM ASP. "
            + "SK hynix aims to expand sales of high-end DRAM products including HBM3."
        )

        anchor = _fixture_anchor_text(text, max_chars=500, target_names=("SK hynix",))

        self.assertIn("HBM3", anchor)
        self.assertIn("AI server memory", anchor)
        self.assertNotIn("accessibility statement skip navigation", anchor[:120])

    def test_claim_extraction_anchor_text_prefers_trial_discontinuation_signal(self):
        from e2r.cli.run_agentic_claim_extraction import _anchor_locator_for_text, _fixture_anchor_text

        text = (
            "SillaJen Inc. accessibility statement skip navigation resources client login. "
            * 80
            + "SillaJen announced that the Independent Data Monitoring Committee for the PHOCUS trial "
            + "completed a futility analysis and recommended discontinuation of the trial. "
            + "The company is taking steps to notify investigators that enrollment is being stopped."
        )

        anchor = _fixture_anchor_text(text, max_chars=700, target_names=("SillaJen",))
        locator = _anchor_locator_for_text(text, anchor, fallback="char:0:800")

        self.assertIn("recommended discontinuation", anchor)
        self.assertIn("enrollment is being stopped", anchor)
        self.assertNotIn("accessibility statement skip navigation", anchor[:120])
        self.assertNotEqual(locator, "char:0:800")

