        self.assertEqual(manifest["summary"]["same_event_asof_verified_count"], 1)
        self.assertEqual(manifest["summary"]["blocked_task_not_ready_count"], 1)
        self.assertEqual(manifest["summary"]["no_verifier_result_count"], 1)
        self.assertEqual(manifest["summary"]["forbidden_output_field_count"], 1)
        self.assertEqual(manifest["summary"]["future_snapshot_not_allowed_count"], 1)
        self.assertEqual(manifest["summary"]["accepted_verification_row_count"], 1)
        self.assertEqual(manifest["summary"]["production_score_fixture_count"], 0)
        self.assertEqual(by_candidate["SRCAND-OK"]["result_status"], "same_event_asof_verified")
        self.assertTrue(by_candidate["SRCAND-OK"]["source_replacement_verified"])
        self.assertFalse(by_candidate["SRCAND-OK"]["production_score_fixture"])
        self.assertEqual(by_candidate["SRCAND-FORBIDDEN"]["result_status"], "forbidden_output_field")
        self.assertIn("score", by_candidate["SRCAND-FORBIDDEN"]["forbidden_output_fields"])
        self.assertEqual(by_candidate["SRCAND-FUTURE"]["result_status"], "future_snapshot_not_allowed")
        self.assertEqual(by_candidate["SRCAND-BLOCKED"]["result_status"], "blocked_task_not_ready")
        self.assertEqual(by_candidate["SRCAND-MISSING"]["result_status"], "no_verifier_result")
        accepted = manifest["accepted_verification_rows"][0]
        self.assertEqual(accepted["task_id"], "RSVFY-OK")
        self.assertTrue(accepted["same_event_verified"])
        self.assertNotIn("score", accepted)

