    def test_v2_orchestrator_quarantines_source_proxy_only_mapping_before_ledger(self):
        text = "Proxy summary says Target issuer has a current contract."
        document = EvidenceDocument.from_text(
            text=text,
            canonical_url="https://example.com/source-proxy-summary",
            source_type=SourceType.OTHER,
            source_name="ResearchProxy",
            published_at=date(2026, 6, 1),
            source_proxy_only=True,
        )
        anchor = EvidenceAnchor.text_span(
            document=document,
            document_text=text,
            exact_text="Target issuer has a current contract",
        )
        raw = RawAssertion(
            raw_assertion_id="RAW-SOURCE-PROXY-WORKFLOW",
            anchor_id=anchor.anchor_id,
            subject_text="Target issuer",
            predicate="has current contract",
            object_text="current contract",
            polarity_proposal=Polarity.POSITIVE,
            exact_quote="Target issuer has a current contract",
        )
        contract = EvidenceContractV2(
            archetype_id="C06_HBM_MEMORY_CUSTOMER_CAPACITY",
            required_primitives=("revenue_visibility_contract",),
            green_gate=GateExpression.primitive("revenue_visibility_contract"),
        )

        result = EvidenceWorkflowOrchestrator(
            extractor=FakeClaimExtractorProvider(ClaimExtractionOutput((raw,))),
            adjudicator=FakeClaimAdjudicatorProvider(
                AdjudicationProposal(
                    subject_entity_id="CORP_TARGET",
                    relation_to_target=RelationToTarget.SELF,
                    directness=Directness.DIRECT,
                    target_scope_status=TargetScopeStatus.DIRECT,
                    polarity=Polarity.POSITIVE,
                    temporal_status=TemporalStatus.CURRENT,
                    semantic_status=SemanticStatus.PASS_,
                    investigation_status=InvestigationStatus.COMPLETE,
                    event_date=date(2026, 6, 1),
                )
            ),
            mapper=_DynamicMapper(
                primitive_id="revenue_visibility_contract",
                status=MappingStatus.ACCEPTED,
                support_direction=SupportDirection.SUPPORT,
            ),
        ).compile(
            EvidenceCompilationInput(
                target_entity_id="CORP_TARGET",
                target_names=("Target issuer",),
                as_of_date=date(2026, 6, 21),
                document=document,
                document_text=text,
                anchors=(anchor,),
                entity_registry=EntityRegistry(),
                contract=contract,
                canonical_primitive_ids=("revenue_visibility_contract",),
            )
        )

        self.assertEqual(len(result.ledger.claims), 1)
        self.assertEqual(len(result.ledger.mappings), 0)
        self.assertEqual(len(result.accepted_mappings), 0)
        self.assertEqual(result.rejected_mapping_count, 1)
        self.assertEqual(len(result.rejected_mappings), 1)

