    def test_score_contribution_adapter_requires_claim_backed_present_primitives(self):
        states = {
            "revenue_mix": PrimitiveStateV2(
                primitive_id="revenue_mix",
                status=PrimitiveStatus.PRESENT_CURRENT,
                support_claim_ids=("CLM-REV",),
                support_source_family_ids=("SFAM-REV",),
                support_mapping_ids=("MAP-REV",),
            ),
            "missing_cash": PrimitiveStateV2(
                primitive_id="missing_cash",
                status=PrimitiveStatus.UNKNOWN,
            ),
            "accounting_trust_break": PrimitiveStateV2(
                primitive_id="accounting_trust_break",
                status=PrimitiveStatus.PRESENT_CURRENT,
                counter_claim_ids=("CLM-RISK",),
                counter_source_family_ids=("SFAM-RISK",),
                counter_mapping_ids=("MAP-RISK",),
            ),
            "contradicted": PrimitiveStateV2(
                primitive_id="contradicted",
                status=PrimitiveStatus.CONTRADICTED,
                support_claim_ids=("CLM-A",),
                counter_claim_ids=("CLM-B",),
            ),
        }

        contributions = build_score_contributions_from_primitives(
            primitive_states=states,
            rules=(
                PrimitiveScoreRule(
                    component_key="earnings_visibility",
                    criterion_id="revenue_mix",
                    primitive_id="revenue_mix",
                    points=4.0,
                    max_points=5.0,
                ),
                PrimitiveScoreRule(
                    component_key="cash_conversion",
                    criterion_id="missing_cash",
                    primitive_id="missing_cash",
                    points=4.0,
                    max_points=5.0,
                ),
                PrimitiveScoreRule(
                    component_key="risk_penalty",
                    criterion_id="accounting_trust_break",
                    primitive_id="accounting_trust_break",
                    points=5.0,
                    max_points=5.0,
                    claim_side="counter",
                ),
                PrimitiveScoreRule(
                    component_key="visibility",
                    criterion_id="contradicted",
                    primitive_id="contradicted",
                    points=3.0,
                    max_points=5.0,
                ),
            ),
        )

        by_criterion = {item.criterion_id: item for item in contributions}
        self.assertEqual(by_criterion["revenue_mix"].raw_points, 4.0)
        self.assertEqual(by_criterion["revenue_mix"].support_claim_ids, ("CLM-REV",))
        self.assertEqual(by_criterion["revenue_mix"].mapping_ids, ("MAP-REV",))
        self.assertEqual(by_criterion["revenue_mix"].source_family_ids, ("SFAM-REV",))
        self.assertEqual(by_criterion["missing_cash"].raw_points, 0.0)
        self.assertEqual(by_criterion["missing_cash"].cap_reason, "primitive_status:UNKNOWN")
        self.assertEqual(by_criterion["accounting_trust_break"].support_claim_ids, ("CLM-RISK",))
        self.assertEqual(by_criterion["accounting_trust_break"].mapping_ids, ("MAP-RISK",))
        self.assertEqual(by_criterion["accounting_trust_break"].source_family_ids, ("SFAM-RISK",))
        self.assertEqual(by_criterion["contradicted"].raw_points, 0.0)
        self.assertEqual(by_criterion["contradicted"].cap_reason, "primitive_status:CONTRADICTED")

