    def test_primitive_aggregator_uses_only_accepted_non_invalidated_mappings(self):
        document, anchor, raw = _current_target_risk_fixture()
        support_claim = AdjudicatedClaim.from_raw(
            raw=raw,
            document=document,
            anchor=anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.POSITIVE,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2026, 6, 1),
        )
        counter_claim = AdjudicatedClaim.from_raw(
            raw=RawAssertion(
                raw_assertion_id="RAW-COUNTER",
                anchor_id=anchor.anchor_id,
                subject_text="Target issuer",
                predicate="contradicting bridge",
                object_text="counterclaim",
            ),
            document=document,
            anchor=anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.NEGATIVE,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2026, 6, 5),
        )
        invalidated_claim = AdjudicatedClaim.from_raw(
            raw=RawAssertion(
                raw_assertion_id="RAW-INVALIDATED",
                anchor_id=anchor.anchor_id,
                subject_text="Target issuer",
                predicate="invalidated bridge",
                object_text="invalidated",
            ),
            document=document,
            anchor=anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.POSITIVE,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2026, 6, 7),
        )
        ledger = AppendOnlyEvidenceLedger()
        for claim in (support_claim, counter_claim, invalidated_claim):
            ledger.append_claim(claim)
        ledger.append_mapping(
            PrimitiveMappingProposal.build(
                claim_id=support_claim.claim_id,
                archetype_id="C_TEST",
                primitive_id="cash_or_revision_conversion",
                support_direction=SupportDirection.SUPPORT,
                mapping_status=MappingStatus.ACCEPTED,
                rationale="support",
            )
        )
        ledger.append_mapping(
            PrimitiveMappingProposal.build(
                claim_id=counter_claim.claim_id,
                archetype_id="C_TEST",
                primitive_id="cash_or_revision_conversion",
                support_direction=SupportDirection.COUNTER,
                mapping_status=MappingStatus.ACCEPTED,
                rationale="counter",
            )
        )
        ledger.append_mapping(
            PrimitiveMappingProposal.build(
                claim_id=invalidated_claim.claim_id,
                archetype_id="C_TEST",
                primitive_id="invalidated_primitive",
                support_direction=SupportDirection.SUPPORT,
                mapping_status=MappingStatus.ACCEPTED,
                rationale="invalidated",
            )
        )
        ledger.invalidate_claim(invalidated_claim.claim_id, reason="superseded")
        contract = EvidenceContractV2(
            archetype_id="C_TEST",
            required_primitives=("cash_or_revision_conversion", "missing_primitive", "invalidated_primitive"),
            green_gate=GateExpression.primitive("cash_or_revision_conversion"),
        )

        states = aggregate_primitive_states(
            ledger=ledger,
            contract=contract,
            as_of_date=date(2026, 6, 21),
        )

        self.assertEqual(states["cash_or_revision_conversion"].status, PrimitiveStatus.CONTRADICTED)
        self.assertEqual(states["cash_or_revision_conversion"].freshness_days, 16)
        self.assertEqual(states["missing_primitive"].status, PrimitiveStatus.UNKNOWN)
        self.assertEqual(states["invalidated_primitive"].status, PrimitiveStatus.UNKNOWN)

