    def test_follow_up_tasks_are_enriched_with_contract_source_quorum(self):
        green_task = SourceAcquisitionTask(
            task_id="task-c06-green",
            target_entity_id="KR:000660",
            primitive_gap="hbm_capacity_pre_sold",
            preferred_source_classes=("IR", "NEWS"),
            date_window=(None, date(2026, 6, 21)),
            required_source_tier="source-backed",
            max_queries=1,
            max_candidates=3,
            max_fetches=3,
            stop_condition="first_verified_claim_or_counterclaim",
            fallback_policy="official_first_then_independent_report",
        )
        risk_task = SourceAcquisitionTask(
            task_id="task-c06-risk",
            target_entity_id="KR:000660",
            primitive_gap="accounting_trust_break",
            preferred_source_classes=("FILING", "NEWS"),
            date_window=(None, date(2026, 6, 21)),
            required_source_tier="source-backed",
            max_queries=1,
            max_candidates=3,
            max_fetches=3,
            stop_condition="hard_break_verification",
            fallback_policy="official_first_then_independent_report",
        )

        enriched_green, enriched_risk = _tasks_with_contract_source_quorum(
            (green_task, risk_task),
            archetype_id="C06_HBM_MEMORY_CUSTOMER_CAPACITY",
            as_of_date=date(2026, 6, 21),
        )

        self.assertEqual(enriched_green.source_quorum_rule_id, "green_gate")
        self.assertEqual(enriched_green.source_quorum_min_official, 0)
        self.assertEqual(enriched_green.source_quorum_min_independent_tier2, 1)
        self.assertEqual(enriched_green.date_window, (date(2025, 6, 21), date(2026, 6, 21)))
        self.assertEqual(enriched_risk.source_quorum_rule_id, "hard_break")
        self.assertEqual(enriched_risk.source_quorum_min_official, 1)
        self.assertEqual(enriched_risk.source_quorum_min_independent_tier2, 0)

