    def test_search_result_source_family_dedupes_syndicated_news_reposts(self):
        task = SourceAcquisitionTask(
            task_id="task-syndicated-news",
            target_entity_id="KR:000660",
            primitive_gap="hbm_capacity_pre_sold",
            preferred_source_classes=("NEWS", "FILING"),
            date_window=(None, date(2026, 6, 21)),
            required_source_tier="source-backed",
            max_queries=1,
            max_candidates=5,
            max_fetches=3,
            stop_condition="first_verified_claim_or_counterclaim",
            fallback_policy="official_first_then_independent_report",
        )
        title = "SK하이닉스 HBM capacity pre-sold allocation confirmed"
        published = datetime(2026, 6, 1, 9, 0)
        results = (
            SearchResult(
                title=title,
                url="https://reuters.example.com/sk-hynix-hbm",
                source="Reuters",
                published_at=published,
                is_news=True,
                date_verified=True,
                green_allowed_by_date=True,
            ),
            SearchResult(
                title=title,
                url="https://portal.example.com/repost/sk-hynix-hbm",
                source="Portal Repost",
                published_at=published,
                is_news=True,
                date_verified=True,
                green_allowed_by_date=True,
            ),
            SearchResult(
                title="SK하이닉스 HBM 공식 공시",
                url="opendart://000660/20260601",
                source="DART",
                published_at=published,
                is_disclosure=True,
            ),
        )
        candidates = tuple(
            _source_candidate_from_search_result(result, index=index)
            for index, result in enumerate(results)
        )

        self.assertEqual(candidates[0].source_family_id, candidates[1].source_family_id)
        self.assertNotEqual(candidates[0].source_family_id, candidates[2].source_family_id)

        plan = build_source_route_plan(task=task, candidates=candidates)

        self.assertEqual(len(plan.selected_candidates), 1)
        self.assertEqual(
            tuple(candidate.candidate_id for candidate in plan.selected_candidates),
            (candidates[0].candidate_id,),
        )
        self.assertIn(candidates[1].candidate_id, plan.skipped_candidate_ids)
        self.assertEqual(plan.skipped_candidate_reasons[candidates[1].candidate_id], "deduped_source_family")
        self.assertEqual(plan.skipped_candidate_reasons[candidates[2].candidate_id], "primitive_operating_signal_missing")

