    def test_evidence_contract_v2_supports_any_all_and_k_of_n_gates(self):
        contract = EvidenceContractV2(
            archetype_id="C_TEST",
            required_primitives=(
                "customer_allocation",
                "capacity_pre_sold",
                "revenue_mix",
                "shipment_visibility",
                "cash_or_revision_conversion",
            ),
            green_gate=GateExpression.all(
                (
                    GateExpression.any(
                        (
                            GateExpression.primitive("customer_allocation"),
                            GateExpression.primitive("capacity_pre_sold"),
                        )
                    ),
                    GateExpression.any(
                        (
                            GateExpression.primitive("revenue_mix"),
                            GateExpression.primitive("shipment_visibility"),
                        )
                    ),
                    GateExpression.primitive("cash_or_revision_conversion"),
                )
            ),
        )

        self.assertTrue(
            contract.green_gate_satisfied(
                ("capacity_pre_sold", "shipment_visibility", "cash_or_revision_conversion")
            )
        )
        self.assertFalse(contract.green_gate_satisfied(("capacity_pre_sold", "shipment_visibility")))

        k_gate = GateExpression.k_of_n(
            k=2,
            children=(
                GateExpression.primitive("a"),
                GateExpression.primitive("b"),
                GateExpression.primitive("c"),
            ),
        )
        self.assertTrue(k_gate.evaluate(("a", "c")))
        self.assertFalse(k_gate.evaluate(("a",)))

    def test_evidence_contract_v2_loader_reads_gates_quorum_and_freshness(self):
        contracts = load_evidence_contracts_v2_from_mapping(
            {
                "schema_version": EVIDENCE_CONTRACT_V2_SCHEMA_VERSION,
                "contract_count": 1,
                "contracts": [
                    {
                        "archetype_id": "C06_HBM_MEMORY_CUSTOMER_CAPACITY",
                        "required_primitives": [
                            "customer_allocation",
                            "capacity_pre_sold",
                            "cash_or_revision_conversion",
                        ],
                        "green_gate": {
                            "all": [
                                {
                                    "any": [
                                        {"primitive": "customer_allocation"},
                                        {"primitive": "capacity_pre_sold"},
                                    ]
                                },
                                {"primitive": "cash_or_revision_conversion"},
                            ]
                        },
                        "alternative_primitives": {
                            "customer_allocation": ["named_customer_shipment"]
                        },
                        "primitive_aliases": {
                            "customer_allocation": ["customer allocation", "고객 배정"],
                            "capacity_pre_sold": ["sold-out capacity", "완판"],
                        },
                        "route_hints": {
                            "emerging_theme_ids": ["HBM_AI_MEMORY"],
                            "primary_route_ids": ["memory_semiconductor_cycle"],
                        },
                        "source_quorum": {
                            "hard_break": {
                                "min_official": 1,
                                "min_independent_tier2": 0,
                            }
                        },
                        "freshness": {
                            "customer_allocation": {
                                "max_age_days": 365,
                                "supersession_rule": "latest_customer_or_company_update",
                                "closure_conditions": ["superseded_by_newer_allocation"],
                                "authoritative_followup_sources": ["FILING", "IR"],
                            }
                        },
                        "guard_modes": {
                            "qualification_delay": "block_if_current"
                        },
                        "aggregation_rules": ["syndicated_articles_count_as_one"],
                    }
                ],
            }
        )
        contract = contracts["C06_HBM_MEMORY_CUSTOMER_CAPACITY"]

        self.assertTrue(contract.green_gate_satisfied(("named_customer_shipment", "cash_or_revision_conversion")))
        self.assertTrue(contract.source_quorum["hard_break"].satisfied(
            (SourceFamilyEvidence("DART-1", "DOC-1", SourceType.FILING, tier=1, official=True),)
        ))
        self.assertEqual(contract.freshness["customer_allocation"].max_age_days, 365)
        self.assertEqual(contract.guard_modes["qualification_delay"], "block_if_current")
        self.assertEqual(contract.primitive_aliases["customer_allocation"], ("customer allocation", "고객 배정"))
        self.assertEqual(contract.primitive_aliases["capacity_pre_sold"], ("sold-out capacity", "완판"))
        self.assertEqual(contract.route_hints["emerging_theme_ids"], ("HBM_AI_MEMORY",))
        self.assertEqual(contract.route_hints["primary_route_ids"], ("memory_semiconductor_cycle",))

