    def test_source_quorum_can_be_checked_inside_score_eligibility(self):
        document, anchor, raw = _current_target_risk_fixture()
        claim = AdjudicatedClaim.from_raw(
            raw=raw,
            document=document,
            anchor=anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.NEGATIVE,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
            event_date=date(2026, 6, 1),
        )
        mapping = PrimitiveMappingProposal.build(
            claim_id=claim.claim_id,
            archetype_id="R13_CROSS_ARCHETYPE_ACCOUNTING_TRUST_PRICE_VALIDATION",
            primitive_id="accounting_trust_break",
            support_direction=SupportDirection.COUNTER,
            mapping_status=MappingStatus.ACCEPTED,
            rationale="Direct current target accounting risk.",
        )
        duplicated_news = (
            SourceFamilyEvidence("WIRE-1", "DOC-1", SourceType.NEWS, tier=2, independent=True),
            SourceFamilyEvidence("WIRE-1", "DOC-2", SourceType.NEWS, tier=2, independent=True),
        )

        quorum_satisfied = SourceQuorumRule(min_independent_tier2=2).satisfied(duplicated_news)
        eligibility = derive_score_eligibility(
            document=document,
            anchor=anchor,
            claim=claim,
            mapping=mapping,
            as_of_date=date(2026, 6, 21),
            require_source_quorum=True,
            source_quorum_satisfied=quorum_satisfied,
        )

        self.assertFalse(quorum_satisfied)
        self.assertFalse(eligibility.eligible)
        self.assertIn("source_quorum_not_satisfied", eligibility.reasons)

