            decode_same_event_source_replacement_output(
                {
                    "status": "ok",
                    "candidate_sources": [
                        {
                            "request_id": "SREPL-1",
                            "fixture_seed_id": "FSEED-1",
                            "candidate_url": "javascript:alert(1)",
                            "candidate_title": "Bad source",
                            "candidate_available_date": None,
                            "source_type": None,
                            "rationale": "same event",
                        }
                    ],
                }
            )

