    def test_codex_follow_up_prompt_requires_nonempty_queries_for_material_gaps(self):
        inputs = FollowUpPlanningInput(
            target_entity_id="KR:000660",
            as_of_date=date(2026, 6, 21),
            primitive_states=(
                PrimitiveStateV2(
                    "hbm_capacity_pre_sold",
                    PrimitiveStatus.UNKNOWN,
                    normalized_value={"large": "x" * 1000},
                    support_claim_ids=("CLM-SUPPORT",),
                    counter_claim_ids=("CLM-COUNTER",),
                    materiality_remaining_points=8.0,
                ),
                PrimitiveStateV2("memory_price_increase_mentioned", PrimitiveStatus.PRESENT_CURRENT),
            ),
            target_names=("SK하이닉스", "000660"),
            stage_gate_context=("score_gap_retry_1: previous route returned no suggested_queries",),
            existing_queries=("SK하이닉스 HBM capacity",),
            max_queries=3,
            max_candidates=10,
            max_fetches=5,
        )

        prompt = _build_follow_up_planning_prompt(inputs)

        self.assertIn("unresolved_material_primitive_states", prompt)
        self.assertIn("SK하이닉스", prompt)
        self.assertIn("hbm_capacity_pre_sold", prompt)
        self.assertIn("suggested_queries must contain at least one new target-company scoped query", prompt)
        self.assertIn("This is a retry after a previous empty suggested_queries response", prompt)
        self.assertIn("Do not score or stage the company", prompt)
        self.assertIn('"support_claim_count": 1', prompt)
        self.assertIn('"counter_claim_count": 1', prompt)
        self.assertNotIn("CLM-SUPPORT", prompt)
        self.assertNotIn("CLM-COUNTER", prompt)
        self.assertNotIn("xxxxx", prompt)
        self.assertNotIn("determine the final stage", prompt.lower())

    def test_codex_follow_up_planner_retries_empty_queries_for_material_gaps(self):
        provider = _SequenceCodexProvider(
            [
                {"status": "ok", "suggested_queries": [], "tasks": []},
                {
                    "status": "ok",
                    "suggested_queries": ["SK하이닉스 HBM capacity allocation official 2026"],
                    "tasks": [
                        {
                            "task_id": "task-hbm-capacity",
                            "target_entity_id": "KR:000660",
                            "primitive_gap": "hbm_capacity_pre_sold",
                            "preferred_source_classes": ["IR", "FILING", "NEWS"],
                            "date_window": [None, "2026-06-21"],
                            "required_source_tier": "source-backed",
                            "max_queries": 1,
                            "max_candidates": 5,
                            "max_fetches": 3,
                            "stop_condition": "first_verified_support_or_counterclaim",
                            "fallback_policy": "official_first_then_independent_news",
                        }
                    ],
                },
            ]
        )
        inputs = FollowUpPlanningInput(
            target_entity_id="KR:000660",
            as_of_date=date(2026, 6, 21),
            primitive_states=(
                PrimitiveStateV2("hbm_capacity_pre_sold", PrimitiveStatus.UNKNOWN, materiality_remaining_points=8.0),
            ),
            target_names=("SK하이닉스", "000660"),
            max_queries=2,
            max_candidates=5,
            max_fetches=3,
        )

        output = provider.plan(inputs)

        self.assertEqual(output.suggested_queries, ("SK하이닉스 HBM capacity allocation official 2026",))
        self.assertEqual(len(provider.prompts), 2)
        self.assertIn("previous follow-up plan returned no suggested_queries", provider.prompts[1])
        self.assertIn("Empty suggested_queries is invalid for this retry", provider.prompts[1])
        self.assertIn("Do not score or stage the company", provider.prompts[1])

