    def test_mapping_payload_requires_target_realized_pricing_for_pricing_power(self):
        text = "Target issuer fulfilled orders received before market prices rose."
        document = EvidenceDocument.from_text(
            text=text,
            canonical_url="https://example.com/target-orders-before-price-rise",
            source_type=SourceType.RESEARCH_REPORT,
            source_name="FixtureReport",
            published_at=date(2026, 6, 1),
        )
        anchor = EvidenceAnchor.text_span(document=document, document_text=text, exact_text=text)
        raw = RawAssertion(
            raw_assertion_id="RAW-ORDER-TIMESTAMP",
            anchor_id=anchor.anchor_id,
            subject_text="Target issuer",
            predicate="fulfilled orders",
            object_text="orders received before market prices rose",
            polarity_proposal=Polarity.POSITIVE,
            exact_quote=text,
        )
        claim = AdjudicatedClaim.from_raw(
            raw=raw,
            document=document,
            anchor=anchor,
            subject_entity_id="CORP_TARGET",
            target_entity_id="CORP_TARGET",
            relation_to_target=RelationToTarget.SELF,
            directness=Directness.DIRECT,
            verification_status=VerificationStatus.SEMANTIC_VERIFIED,
            target_scope_status=TargetScopeStatus.DIRECT,
            polarity=Polarity.POSITIVE,
            temporal_status=TemporalStatus.CURRENT,
            semantic_status=SemanticStatus.PASS_,
            investigation_status=InvestigationStatus.COMPLETE,
        )
        contract = EvidenceContractV2(
            archetype_id="C02_POWER_GRID_DATACENTER_CAPEX",
            required_primitives=("pricing_power_confirmed",),
            green_gate=GateExpression.primitive("pricing_power_confirmed"),
        )

        payload = _mapping_payload(
            PrimitiveMappingInput(
                claim=claim,
                raw_assertion=raw,
                anchor=anchor,
                contract=contract,
                canonical_primitive_ids=("pricing_power_confirmed",),
            )
        )

        rules_text = "\n".join(payload["rules"])
        self.assertIn("require the raw assertion or exact_quote", rules_text)
        self.assertIn("realized higher ASP/prices", rules_text)
        self.assertIn("order timestamp before prices rose", rules_text)

