class _BatchMapper:
    def __init__(self, primitive_id):
        self.primitive_id = primitive_id
        self.batch_call_count = 0
        self.single_call_count = 0
        self.batch_input_sizes = ()
        self.batch_task_counts = ()

    def map_many(self, inputs):
        self.batch_call_count += 1
        input_tuple = tuple(inputs)
        self.batch_input_sizes = (*self.batch_input_sizes, len(input_tuple))
        self.batch_task_counts = (
            *self.batch_task_counts,
            sum(max(len(item.canonical_primitive_ids), 1) for item in input_tuple),
        )
        return PrimitiveMappingOutput(
            tuple(
                PrimitiveMappingProposal.build(
                    claim_id=item.claim.claim_id,
                    archetype_id=item.contract.archetype_id,
                    primitive_id=(
                        self.primitive_id
                        if self.primitive_id in item.canonical_primitive_ids
                        else item.canonical_primitive_ids[0]
                    ),
                    support_direction=SupportDirection.SUPPORT,
                    mapping_status=MappingStatus.ACCEPTED,
                    rationale="batch mapped in test",
                )
                for item in input_tuple
            )
        )

    def map(self, inputs):
        self.single_call_count += 1
        raise AssertionError("single mapping should not be used")


class _EmptyThenBatchMapper(_BatchMapper):
    def __init__(self, primitive_id):
        super().__init__(primitive_id)
        self.empty_call_count = 0

    def map_many(self, inputs):
        if self.batch_call_count == 0:
            self.batch_call_count += 1
            input_tuple = tuple(inputs)
            self.batch_input_sizes = (*self.batch_input_sizes, len(input_tuple))
            self.batch_task_counts = (
                *self.batch_task_counts,
                sum(max(len(item.canonical_primitive_ids), 1) for item in input_tuple),
            )
            self.empty_call_count += 1
            return PrimitiveMappingOutput(())
        return super().map_many(inputs)


class _RoundVariantBatchMapper:
    def __init__(self, primitive_rounds):
        self.primitive_rounds = tuple(tuple(round_ids) for round_ids in primitive_rounds)
        self.batch_call_count = 0

    def map_many(self, inputs):
        self.batch_call_count += 1
        round_index = min(self.batch_call_count - 1, len(self.primitive_rounds) - 1)
        primitive_ids = self.primitive_rounds[round_index]
        mappings = []
        for item in inputs:
            for primitive_id in primitive_ids:
                mappings.append(
                    PrimitiveMappingProposal.build(
                        claim_id=item.claim.claim_id,
                        archetype_id=item.contract.archetype_id,
                        primitive_id=primitive_id,
                        support_direction=SupportDirection.SUPPORT,
                        mapping_status=MappingStatus.ACCEPTED,
                        rationale=f"round {self.batch_call_count} mapped {primitive_id}",
                    )
                )
        return PrimitiveMappingOutput(tuple(mappings))

    def map(self, inputs):
        raise AssertionError("single mapping should not be used")


class _RoundVariantSingleMapper:
    def __init__(self, primitive_rounds):
        self.primitive_rounds = tuple(tuple(round_ids) for round_ids in primitive_rounds)
        self.single_call_count = 0
        self.batch_call_count = 0

    def map_many(self, inputs):
        self.batch_call_count += 1
        raise AssertionError("batch mapping should not be used")

    def map(self, inputs):
        self.single_call_count += 1
        round_index = min(self.single_call_count - 1, len(self.primitive_rounds) - 1)
        return PrimitiveMappingOutput(
            tuple(
                PrimitiveMappingProposal.build(
                    claim_id=inputs.claim.claim_id,
                    archetype_id=inputs.contract.archetype_id,
                    primitive_id=primitive_id,
                    support_direction=SupportDirection.SUPPORT,
                    mapping_status=MappingStatus.ACCEPTED,
                    rationale=f"single round {self.single_call_count} mapped {primitive_id}",
                )
                for primitive_id in self.primitive_rounds[round_index]
            )
        )


