class _RuntimeC06CoreExtractor:
    def __init__(self):
        self.calls = []

    def extract(self, inputs):
        self.calls.append(inputs)
        anchor = inputs.anchors[0]
        text = inputs.document_text.casefold()
        if "fully booked" in text or "생산분 예약" in inputs.document_text:
            predicate = "reported production fully booked"
            object_text = "HBM production fully booked for customer demand"
        elif "demand exceeds supply" in text or "수요 초과" in inputs.document_text:
            predicate = "reported demand exceeds supply"
            object_text = "HBM demand exceeds supply and supply tightness"
        elif "customer volume allocated" in text or "고객사 확정 물량" in inputs.document_text:
            predicate = "reported customer volume allocation"
            object_text = "customer volume allocated and customer commitment"
        elif "선수주" in inputs.document_text or "pre-order before expansion" in text:
            predicate = "reported customer preorder before expansion"
            object_text = "customer preorder before expansion and customer commitment"
        elif "memory price" in text:
            predicate = "reported memory price strength"
            object_text = "HBM memory price increase"
        else:
            predicate = "reported C06 evidence"
            object_text = inputs.document_text[:160]
        return ClaimExtractionOutput(
            (
                RawAssertion(
                    raw_assertion_id=f"RAW-C06-{len(self.calls)}",
                    anchor_id=anchor.anchor_id,
                    subject_text=inputs.target_names[0],
                    predicate=predicate,
                    object_text=object_text,
                    polarity_proposal=Polarity.POSITIVE,
                    event_date_text="2026-06-01",
                    exact_quote=anchor.exact_text,
                ),
            )
        )


class _RuntimeC06CoreMapper:
    def __init__(self):
        self.calls = []

    def map(self, inputs):
        self.calls.append(inputs)
        raw = inputs.raw_assertion
        object_text = str(raw.object_text if raw is not None else "").casefold()
        predicate = str(raw.predicate if raw is not None else inputs.claim.adjudication_rationale).casefold()
        marker = f"{predicate} {object_text}"
        if "fully booked" in marker:
            primitive_id = "hbm_capacity_pre_sold"
        elif "demand exceeds supply" in marker or "supply tightness" in marker:
            primitive_id = "hbm_capacity_constraint"
        elif "customer volume" in marker or "customer commitment" in marker:
            primitive_id = "customer_preorder_or_allocation"
        elif "memory price" in marker:
            primitive_id = "memory_price_increase_mentioned"
        else:
            primitive_id = inputs.canonical_primitive_ids[0]
        return PrimitiveMappingOutput(
            (
                PrimitiveMappingProposal.build(
                    claim_id=inputs.claim.claim_id,
                    archetype_id=inputs.contract.archetype_id,
                    primitive_id=primitive_id,
                    support_direction=SupportDirection.SUPPORT,
                    mapping_status=MappingStatus.ACCEPTED,
                    rationale="runtime C06 core fixture mapping",
                ),
            )
        )


