class _SequenceCodexProvider(CodexCLIAgenticEvidenceProvider):
    def __init__(self, outputs):
        super().__init__()
        self.outputs = list(outputs)
        self.prompts = []

    def _run_json(self, *, schema, prompt):
        self.prompts.append(prompt)
        return self.outputs.pop(0) if self.outputs else None


def _raw_assertion_json(raw):
    payload = asdict(raw)
    polarity = payload.get("polarity_proposal")
    if hasattr(polarity, "value"):
        payload["polarity_proposal"] = polarity.value
    return payload


def _audit_fixture():
    text = (
        "Worldex said its audit opinion was unqualified. "
        "Major customers include a large electronics maker."
    )
    document = EvidenceDocument.from_text(
        text=text,
        canonical_url="https://example.com/supplier-audit",
        source_type=SourceType.NEWS,
        source_name="FixtureNews",
        published_at=date(2020, 3, 18),
    )
    quote = "Worldex said its audit opinion was unqualified."
    anchor = EvidenceAnchor.text_span(document=document, document_text=text, exact_text=quote)
    raw = RawAssertion(
        raw_assertion_id="RAW-SUPPLIER-AUDIT",
        anchor_id=anchor.anchor_id,
        subject_text="Worldex",
        predicate="audit opinion was unqualified",
        object_text="unqualified audit opinion",
        polarity_proposal=Polarity.NORMAL,
        event_date_text="2020-03-18",
        exact_quote=quote,
        related_entity_texts=("large electronics maker",),
    )
    return document, anchor, raw


