def _fingerprint(**overrides):
    values = {
        "commit_sha": "commit-1",
        "config_hash": "config-1",
        "as_of_date": date(2026, 6, 21),
        "source_corpus_hash": "corpus-1",
        "query_set_hash": "query-1",
        "cache_snapshot_id": "cache-1",
        "llm_model": "model-1",
        "llm_prompt_hash": "prompt-1",
        "llm_schema_version": "schema-1",
        "scoring_schema_version": "score-v1",
        "stage_schema_version": "stage-v1",
    }
    values.update(overrides)
    return RunFingerprint(**values)


